INSERT INTO `location` (`id`, `slug`, `placename`, `address`, `city`, `country`, `latitude`, `longitude`, `owner_id`, `created_at`, `updated_at`, `main`, `uid`, `store`, `processed_at`, `department`, `region`, `city_district`, `postal_code`, `eve_id`, `agenda_id`, `insee`) VALUES
(834568, 'chateau224_5033_5563_8809_14370_20060', 'Château d\'Alba-la-Romaine', 'Place du château, 07400 Alba-la-Romaine, Ardèche, Auvergne-Rhône-Alpes', 'Alba-la-Romaine', 'FR', '44.554773', '4.599308', NULL, '2019-04-29 15:38:04', '2019-04-29 15:38:04', 0, 5122576, '{\"image\":\"location36419450.jpg\",\"description\":{\"fr\":\"Façade nord-ouest du XIe - XIIIe visible du parc. La partie habitable et visitable date de la Renaissance avec des transformations au XIXe siècle. Façade du XIe siècle reliée au château datant de la Renaissance par une façade en trompe-l’œil du XIXe siècle.\",\"en\":\"Northwest facade of XIth - XIIIth visible of the park. Habitable part(party) and visitable dates Renaissance with transformations in the XIXth century. Facade of the XIth century connected(bound) with the castle dating Renaissance by a trompe l\'oeil(window-dressing) facade of the XIXth century.\",\"de\":\"Nordwestliche Fassade XI. - XIII. die Park sichtbare. Der bewohnbare Teil(Seite) und visitable die Renaissance mit Veränderungen im XIX. Jahrhundert datiert. Fassade des XI. Jahrhunderts, die im die Renaissance von einer Fassade datierenden Schloss eingebunden(verbunden) ist, täusche es Auge des XIX. Jahrhunderts.\",\"es\":\"Fachada noroeste de XIo - XIIIo visible del parque. La parte habitable y visitable fecha Renacimiento con transformaciones en el siglo XIX. Fachada del siglo XI relacionada al castillo que feche Renacimiento por una fachada engáñalo ojo del siglo XIX.\",\"it\":\"Facciata di nordovest di XIth - XIIIth visibile(evidente) del parco. Parte abitabile (partito) e Rinascimento di date visitable con trasformazioni(metamorfosi) nel secolo XIXth. La facciata del secolo XIth si è connessa (legato) con il Rinascimento di datazione di castello da un trompe l\'oeil (l\'addobbo di vetrine(arte di presentare una situazione sotto una luce favorevole)) la facciata del secolo XIXth.\"},\"tags\":[{\"id\":42,\"label\":\"Monument historique\"},{\"id\":2,\"label\":\"Château, hôtel urbain, palais, manoir\"}],\"website\":\"http://www.chateaudalba.com/\",\"phone\":\"04 75 52 42 90\",\"links\":[],\"access\":{\"fr\":\"9 km après Le Teil, route d\'Aubenas\",\"en\":\"9 km after Teil, road of Aubenas\",\"de\":\"9 km nach Teil, Weg von Aubenas\",\"es\":\"9 kms después de Teil, camino de Aubenas\",\"it\":\"9 chilometri dopo Teil, stradale di Aubenas\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"© Château d\'Alba-la-Romaine\"}', '2016-03-16 09:22:38', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07400', NULL, 25221, '07005'),
(834569, 'museal-site-antique-dalba_5033_5563_8809_14370_20060', 'MuséAl-site antique d\'Alba', 'Route départementale 102, Quartier Saint Pierre, 07400 Alba-la-Romaine, Ardèche, Auvergne-Rhône-Alpes', 'Alba-la-Romaine', 'FR', '44.561007', '4.600168', NULL, '2019-04-29 15:38:05', '2019-04-29 15:38:05', 0, 65430773, '{\"image\":null,\"description\":{\"fr\":\"Ancienne capitale gallo-romaine du peuple des Helviens, Alba symbolise l\'appartenance de la Gaule à l\'Empire romain. Le centre monumental et le théâtre dégagés par les fouilles sont aujourd\'hui visibles et reconstitués, ce qui permet de saisir la magnificence de ce que devait être cette ville il y a environ deux mille ans. Le sanctuaire de Bagnols, où ont été retrouvé de nombreuses pièces archéologiques d\'importance, est un autre centre névralgique de la cité, au milieu des vignes, qui permet de souligner toute l\'importance du religieux dans la vie quotidienne gallo-romaine.\",\"en\":\"Old(Former) Gallo-Roman capital of the people of Helviens, Alba represents the membership of the Gaul in the Roman Empire. Monumental centre and theatre brought out(loosened) by excavations(searches) are visible and reconstructed today, what allows to seize the splendour of what had to be this city about two thousand years ago. The sanctuary of Bagnols, where were found by many archaeological important rooms(parts,plays), is another nerve centre of the city(estate), in the middle of vineyards(vines), which allows to underline all importance of the member of a religious order in everyday life Gallo-Roman.\",\"de\":\"Ehemalige gallo-römische Hauptstadt des Volkes Helviens, Alba symbolisiert die Zugehörigkeit der Stange(Angelrute) zum römischen Reich. Das monumentale Zentrum und das durch die Ausgrabungen(Durchsuchungen) befreite Theater heute sichtbar und werden worden wieder hergestellt, was ermöglicht, die Pracht dessen zu ergreifen(begreifen), was diese Stadt sein sollte, es gibt ungefähr zweitausend Jahre. Das Heiligtum von Bagnols, wo von zahlreichen wichtigen archäologischen Stücken(Zimmern) wiedergefunden worden sind, ist ein anderes neuralgisches Zentrum der Stadt, in der Mitte der Weinreben(Weinberge), das ermöglicht, die ganze Bedeutung des Mönches im gallo-römischen Alltag zu unterstreichen.\",\"es\":\"Antigua capital gallo-romana del pueblo del Helviens, Alba simboliza la pertenencia de la Vara al Imperio romano. El centro monumental y el teatro soltados(desempeñados) por los registros(excavaciones) son hoy visibles y reconstituidos, lo que permite coger la magnificencia lo que debía ser esta ciudad hay cerca de dos mil años. El santuario de Bagnols, donde han sido reencontrados numerosas piezas(cuartos) arqueológicas de importancia, está otro centro neurálgico de la ciudad, en medio de las vides, que permite subrayar toda la importancia del monje en la vida cotidiana gallo-romana.\",\"it\":\"La capitale Gallo-romana (Vecchia) precedente della gente di Helviens, Alba rappresenta l\'adesione a Gaul nell\'Impero romano. Il centro monumentale e il teatro discolpato (rilasciato) da ricerche (gli scavi) sono visibili(evidenti) e ricostruiti oggi, quello che permette di afferrare lo splendore(magnificenza) di quello che doveva essere questa città circa duemila anni fa. Il santuario(asilo) di Bagnols, dove sono stati trovati da molte camere importanti archeologiche (le parti, i giochi(le opere teatrali)), è altro centro di nervo della città (la proprietà(il patrimonio)), nel mezzo di vigne (le viti(i rampicanti)), che permette di sottolineare tutta l\'importanza del membro di un ordine religioso in Gallo-romano di vita quotidiano. VIA di\"},\"tags\":[{\"id\":11,\"label\":\"Espace naturel, parc, jardin\"},{\"id\":13,\"label\":\"Lieu de pouvoir, édifice judiciaire\"},{\"id\":15,\"label\":\"Musée, salle d\'exposition\"},{\"id\":16,\"label\":\"Site archéologique\"},{\"id\":36,\"label\":\"Villes et Pays d\'art et d\'histoire\"},{\"id\":40,\"label\":\"Musée de France\"},{\"id\":42,\"label\":\"Monument historique\"}],\"website\":\"http://www.ardeche.fr/Ardeche_des_idees_forces/site-archeologique-alba\",\"phone\":\"04 75 52 45 15\",\"links\":[],\"access\":{\"fr\":\"RD 107 (direction Viviers)\",\"en\":\"RD 107 (direction(management) Game preserves)\",\"de\":\"RD 107 (Direktion(Richtung) Fischteiche)\",\"es\":\"RD 107 (dirección Viveros de peces)\",\"it\":\"107 (direzione(indicazione) (direzione) Riserve di caccia)\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null}', '2016-03-16 09:22:42', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07400', NULL, 25221, '07005'),
(834648, 'chapelle-de-lhopital_5033_5563_8809_14370_20060', 'Chapelle de l\'hôpital', 'Rue Saint Prix Barou, 07100 Annonay', 'Annonay', 'FR', '45.242820', '4.665890', NULL, '2019-04-29 15:38:49', '2019-04-29 15:38:49', 0, 5240383, '{\"description\":{\"fr\":\"Chapelle créée en 1704 par les sœurs de Saint Joseph, dans le prolongement des bâtiments de l\'ancien hôpital général. La chapelle est ouverte à l\'occasion, par l\'Office de Tourisme du Pays Annonéen.\"},\"tags\":[{\"id\":3,\"label\":\"Édifice religieux\"}],\"timezone\":\"Europe/Paris\"}', '2016-03-16 09:48:36', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07100', '4bd1e2a3ffffd360180f59b62a71ffd5', 25221, '07010'),
(834649, 'chapelle-de-trachin826_5033_5563_8809_14370_20060', 'Chapelle de Trachin', 'Rue Boissy d\'Anglas, 07100 Annonay', 'Annonay', 'FR', '45.239677', '4.668488', NULL, '2019-04-29 15:38:50', '2019-04-29 15:38:50', 0, 11840818, '{\"image\":null,\"description\":{\"fr\":\"La Chapelle de Trachin est la plus ancienne chapelle de la ville, elle date du XIVe siècle. Elle concentre des objets religieux issus des différentes chapelles de la ville. Elle peut être visitée sur demande pour des groupes de visiteurs.\"},\"tags\":[{\"id\":3,\"label\":\"Édifice religieux\"}],\"phone\":null,\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\"}', '2016-03-16 09:48:40', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07100', NULL, 25221, '07010'),
(834650, 'conservatoire-de-lhopital_5033_5563_8809_14370_20060', 'Conservatoire de l\'hôpital', 'Centre hospitalier d\'Ardèche Nord, rue du Bon Pasteur, 07103 Annonay, Ardèche, Auvergne-Rhône-alpes.', 'Annonay', 'FR', '45.240350', '4.668430', NULL, '2019-04-29 15:38:50', '2019-04-29 15:38:50', 0, 21310796, '{\"image\":null,\"description\":{\"fr\":\"Ancienne pharmacie hospitalière abritant un petit musée hospitalier avec divers objets : équipements médicaux anciens, collection de pôts et de mobilier de pharmacie.\",\"it\":\"Precedente (Vecchio) ospitale (ospedale) farmacia che ripara un piccolo ospitale (ospedale) museo con oggetti(scopi) vari: l\'attrezzatura medico (vecchio) precedente, raccolta(collezione) pôts e di mobili di farmacia.\",\"es\":\"Antigua farmacia hospitalaria que abriega un pequeño museo hospitalario con diversos objetos: antiguos equipos médicos, colección pôts y de mobiliario de farmacia.\",\"de\":\"Die ehemalige ein kleines Krankenhausmuseum mit verschiedenen Gegenständen(Zielen) schützende Krankenhausapotheke: alte medizinische Ausrüstungen, Sammlung pôts und Mobiliars Apotheke.\",\"en\":\"Old(Former) hospitable(hospital) pharmacy sheltering a small hospitable(hospital) museum with diverse objects: old(former) medical equipments, collection pôts and of furniture of pharmacy.\"},\"tags\":[{\"id\":15,\"label\":\"Musée, salle d\'exposition\"}],\"phone\":\"04 75 67 35 81\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null}', '2016-03-16 09:48:44', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07100', NULL, 25221, '07010'),
(834651, 'domaine-marc-seguin-a-varagnes_5033_5563_8809_14370_20060', 'Varagnes - domaine de Marc Seguin', '21 chemin de Varagnes 07100 Annonay', 'Annonay', 'FR', '45.263004', '4.665091', NULL, '2019-04-29 15:38:51', '2019-08-26 16:02:32', 0, 77669202, '{\"image\":\"location99583465.jpg\",\"description\":{\"fr\":\"Varagnes, demeure de Marc Seguin.\",\"en\":\"Varagnes, live(remain) of Mark Seguin.\",\"de\":\"Varagnes, bleibe vom Trester Seguin.\",\"es\":\"Varagnes, queda de Marc Seguin.\",\"it\":\"Varagnes, vivi (rimangono) da Mark Seguin.\"},\"tags\":[{\"id\":42,\"label\":\"Monument historique\"},{\"id\":1,\"label\":\"Maison, appartement, atelier de personnes célèbres\"},{\"id\":11,\"label\":\"Espace naturel, parc, jardin\"}],\"website\":\"http://marcseguin.fr/\",\"email\":null,\"phone\":\"06 81 41 00 44\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"© Cl. V Lefèvre-Seguin\",\"extId\":null}', '2016-03-16 09:48:49', 'Ardèche', 'Auvergne-Rhône-Alpes', 'L\'Auvergnat', '07100', NULL, 25221, '07010'),
(834652, 'parcheminerie-dumas-espace-musee-du-parchemin-et-du-cuir_5033_5563_8809_14370_20060', 'L\'Espace musée du Parchemin et du Cuir', '4 La Combe du prieuré, 07100 Annonay, Ardèche, Auvergne-Rhône-Alpes', 'Annonay', 'FR', '45.246037', '4.667038', NULL, '2019-04-29 15:38:52', '2019-04-29 15:38:52', 0, 41086700, '{\"image\":\"location46797064.jpg\",\"description\":{\"fr\":\"Un des rares musées dédié au parchemin et au cuir, permettant de découvrir l\'une des trois dernières parchemineries de France... Créée en 1926 par Marcel Dumas, classée dans les Métiers d\'Art Rare en 2011, labellisée Entreprise du Patrimoine Vivant en 2013, la Parcheminerie Dumas est une entreprise familiale, riche de l\'expérience de 3 générations. La visite des ateliers permet de découvrir le savoir-faire du parcheminier qui transforme un déchet en matière de luxe, et de parfaire ses connaissances dans le travail de la peau.\",\"en\":\"One of the rare museums devoted to the parchment and to the leather, allowing to discover one of the three parchemineries last ones of France... Having created in 1926 by Marcel Dumas, listed(classified) in the Jobs(Businesses) by Rare Art in 2011, labelled Begun(Undertaken) Living Heritage in 2013, Parcheminerie Dumas is a family company, rich in the experience(experiment) of 3 generations. The visit of workshops(studios) allows to discover the know-how of the parcheminier which transforms a waste regarding luxury, and to improve its knowledge in the work of the skin.\",\"de\":\"Eines der seltenen Museen, was Pergament und Leder geweiht ist, ermöglichend, einen von drei Letzten zu öffnen(entdecken), die Frankreichs sind parchemineries... 1926 von Marcel Dumas geschaffen, in den Berufen Seltener Kunst 2011 geordnet, Gütezeichen, Der durch das Lebende Erbe 2013 Untergenommen(Beeinflusst) Ist, ist Parcheminerie Dumas ein Familienbetrieb, ein Reicher der Erfahrung von 3 Generationen. Der Besuch(Besichtigung) der Werkstätten ermöglicht, die Fachkompetenz des Parcheminier zu öffnen(entdecken), die einen Abfall auf dem Gebiet Luxus verändert und ihre Kenntnisse in der Beschäftigung(Arbeit) der Haut zu vollenden.\",\"es\":\"Uno de los museos raros que fue dedicado al pergamino y al cuero, permitió descubrir una de tres últimas parchemineries de Francia... Creado en 1926 por Marcel Dumas, clasificado en los Oficios de arte Raro en 2011, labellisée Emprendido del Patrimonio Vivo en 2013, Parcheminerie Dumas es una empresa familiar, rica en la experiencia de 3 generaciones. La visita de los talleres(estudios) permite descubrir la destreza del parcheminier que transforma un desecho en materia de lujo, y de perfeccionar sus conocimientos en el trabajo de la piel.\",\"it\":\"Uno dei musei rari(non comuni) ha dedicato alla pergamena e alla pelle, permettendo di scoprire uno di tre parchemineries gli ultimi della Francia... Avendo creato nel 1926 da Marcel Dumas, classificato in Jobs (gli Affari(le Imprese)) da Arte Rara(Non comune) nel 2011, l\'Eredità Vivente (Intrapresa) Cominciata marcata(classificata) (le Tenute(Proprietà)) nel 2013, Parcheminerie Dumas è una società di famiglia, ricca dell\'esperienza (l\'esperimento) di 3 generazioni. La visita(soggiorno) di workshop(officine) (gli studi(le sale di registrazione)) permette di scoprire il know-how del parcheminier che trasforma uno spreco(scorie) riguardo a lusso, e migliorare la sua conoscenza nel lavoro(opera) della pelle. i\"},\"tags\":[{\"id\":15,\"label\":\"Musée, salle d\'exposition\"},{\"id\":8,\"label\":\"Édifice industriel, scientifique et technique\"}],\"website\":\"http://www.espaceduparchemin.fr\",\"phone\":\"06 81 11 17 08\",\"links\":[],\"access\":{\"fr\":\"Proche de la Gare Routière d\'Annonay\",\"en\":\"close friend(relation) de la Gare Routière d\' Annonay\",\"de\":\", dem Autobahnhof von Annonay Nahe\",\"es\":\"Próximo(a) al Estacionamiento de camiones de Annonay\",\"it\":\"chiudono l\'amico (la relazione) il de la Gare Routière d\' Annonay\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null}', '2016-03-16 09:48:53', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07100', NULL, 25221, '07010'),
(834653, 'visite-guidee-de-la-ville_5033_5563_8809_14370_20060', 'Place des Cordeliers', '07100 Annonay', 'Annonay', 'FR', '45.239474', '4.667376', NULL, '2019-04-29 15:38:52', '2019-04-29 15:38:52', 0, 52750974, '{\"image\":null,\"description\":{},\"tags\":[{\"id\":3,\"label\":\"Édifice religieux\"},{\"id\":4,\"label\":\"Édifice hospitalier\"},{\"id\":8,\"label\":\"Édifice industriel, scientifique et technique\"},{\"id\":13,\"label\":\"Lieu de pouvoir, édifice judiciaire\"},{\"id\":15,\"label\":\"Musée, salle d\'exposition\"}],\"phone\":null,\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null}', '2016-03-16 09:48:57', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07100', NULL, 25221, '07010'),
(834678, 'village-et-musee-dart-sacre_5033_5563_8809_14370_20060', 'Village et  musée d\'art sacré', 'Le Village, 07410 Arlebosc', 'Arlebosc', 'FR', '45.036974', '4.652376', NULL, '2019-04-29 15:39:07', '2019-04-29 15:39:07', 0, 28097049, '{\"image\":\"location16378148.jpg\",\"description\":{\"fr\":\"Arlebosc est un charmant village au centre duquel se trouve un vieux château féodal du 12è siècle, autrefois presbytère, et une église avec des fresques rénovées et des vitraux. Dans cette église, à gauche de l\'autel, dans ce qui était autrefois une chapelle privée ont été réunis des objets de culte des siècles passés.  On peut  y admirer des aubes et chasubles richement brodées d\'or, que portaient  les prêtres lors des grandes fêtes religieuses. Et découvrir la variété des objets de culte dont certains sont si rares et précieux qu\'ils sont classés au titre objet.\"},\"tags\":[{\"id\":2,\"label\":\"Château, hôtel urbain, palais, manoir\"},{\"id\":3,\"label\":\"Édifice religieux\"},{\"id\":15,\"label\":\"Musée, salle d\'exposition\"}],\"timezone\":\"Europe/Paris\"}', '2016-03-16 09:59:13', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07410', '9eac212affffd3605b05edc74696e3a0', 25221, '07014'),
(834684, 'centre-ancien-architecture_5033_5563_8809_14370_20060', 'Centre ancien - architecture', 'Centre-ville Aubenas, 07200 Aubenas, Ardèche, Auvergne-Rhône-Alpes', 'Aubenas', 'FR', '44.620900', '4.392500', NULL, '2019-04-29 15:39:10', '2019-06-11 09:21:05', 0, 12802805, '{\"image\":\"location15699595.jpg\",\"description\":{\"fr\":\"Visites guidées du centre historique. Deux angles de visite sont proposés: - patrimoine religieux le samedi - patrimoine architectural le dimanche\",\"it\":\"Visite guidate del centro storico. Sono proposti due angoli di visita(soggiorno): - eredità religiosa (tenute(proprietà)) il sabato - eredità architettonica la domenica\",\"es\":\"Visitas guiadas del centro histórico. Dos ángulos de visita son propuestos: - patrimonio religioso el sábado - patrimonio arquitectónico el domingo\",\"de\":\"Führungen des historischen Zentrums. Zwei Besichtigungsecken(Besichtigungswinkel) werden angeboten: - religiöses Erbe am Samstag - architektonisches Erbe am Sonntag\",\"en\":\"Guided tours of the historic centre. Two angles of visit are proposed: - religious heritage on Saturdays - architectural heritage on Sundays\"},\"tags\":[{\"id\":2,\"label\":\"Château, hôtel urbain, palais, manoir\"},{\"id\":3,\"label\":\"Édifice religieux\"},{\"id\":13,\"label\":\"Lieu de pouvoir, édifice judiciaire\"}],\"website\":\"http://www.aubenas.fr/fr/accueil-patrimoine.htm\",\"email\":null,\"phone\":\"04 75 87 81 11\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null,\"extId\":null}', '2016-03-16 10:09:04', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07200', NULL, 25221, '07019'),
(834686, 'centre-ancien-patrimoine-religieux_5033_5563_8809_14370_20060', 'Centre ancien - patrimoine religieux', 'Place Jeanne-d’Arc, 07200 Aubenas, Ardèche, Auvergne-Rhône-Alpes', 'Aubenas', 'FR', '44.619822', '4.388931', NULL, '2019-04-29 15:39:11', '2019-04-29 15:39:11', 0, 25815108, '{\"image\":null,\"description\":{\"fr\":\"Église du XIIIe siècle remaniée aux XVe, XVIIe, XVIIIe et XIXe siècles. Dans le chœur baroque se trouve le retable de l\'ancienne chapelle jésuite.\",\"it\":\"La chiesa del secolo XIIIth ha cambiato nello XVth, XVIIth, XVIIIth e i secoli XIXth. Nel (coro) del coro barocco il ritavolo(ritabella) di antico Gesuita di cappella (vecchio) è.\",\"es\":\"Iglesia del siglo XIII rehecha en los XV, XVIIos, XVIIIos y XIX siglos. En el coro barroco se encuentra el retable de la antigua capilla jesuita.\",\"de\":\"Kirche des XIII. Jahrhunderts, die in den XV., XVII., XVIII. und XIX. Jahrhunderten neu bearbeitet(umgebildet) ist. Dem barocken Chor findet sich der Retable der ehemaligen Kapelle Jesuiten.\",\"en\":\"Church of the XIIIth century altered in the XVth, XVIIth, XVIIIth and XIXth centuries. In the baroque chorus(choir) the retable of the old(former) chapel Jesuit is.\"},\"tags\":[{\"id\":3,\"label\":\"Édifice religieux\"}],\"website\":\"http://www.aubenas.fr/fr/accueil-patrimoine.htm\",\"phone\":\"04 75 87 81 11\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null}', '2016-03-16 10:09:08', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07200', NULL, 25221, '07019'),
(834687, 'chateau-daubenas_5033_5563_8809_14370_20060', 'Château d\'Aubenas', 'Place de l\'hôtel de ville, 07200 Aubenas, Ardèche, Auvergne-Rhône-Alpes', 'Aubenas', 'FR', '44.620773', '4.389867', NULL, '2019-04-29 15:39:11', '2019-04-29 15:39:11', 0, 72498112, '{\"image\":\"location1439855.jpg\",\"description\":{\"fr\":\"Ancien château féodal transformé à la Renaissance et à l\'époque classique. Histoire des familles seigneuriales d\'Aubenas du XII au XVIIIe siècle. Une des salles expose en permanence des peintures de Chaurand-Naurac ainsi que des sculptures de Marcel Gimond.\",\"it\":\"Il castello feudale (Vecchio) precedente trasformato in Rinascimento e in periodo classico. Storia (Storia(Piano)) delle famiglie di grande proprietà terriera feudale di Aubenas du XII nel secolo XVIIIth. Una delle camere espone (spiega) definitivamente vernici (i quadri) di Chaurand-Naurac così come le sculture di Marcel Gimond.\",\"es\":\"Antiguo castillo feudal transformado al Renacimiento y a la época clásica. Historia de las familias señoriles de Aubenas du XII en el siglo XVIII. Una de las salas expone permanentemente pinturas de Chaurand-Naurac así como esculturas de Marcel Gimond.\",\"de\":\"Die ehemalige in der Renaissance veränderte Burg und damals Klassiker. Geschichte der herrschaftlichen Familien Aubenas du XII im XVIII. Jahrhundert. Einer der Säle stellt ständig Malerei(Gemälde) von Chaurand-Naurac aus sowie von den Skulpturen von Marcel Gimond.\",\"en\":\"Old(Former) feudal castle transformed in Renaissance and in classical period. History(Story) of the manorial families of Aubenas du XII in the XVIIIth century. One of the rooms exposes(explains) permanently paintings(paints) of Chaurand-Naurac as well as sculptures of Marcel Gimond.\"},\"tags\":[{\"id\":2,\"label\":\"Château, hôtel urbain, palais, manoir\"},{\"id\":13,\"label\":\"Lieu de pouvoir, édifice judiciaire\"},{\"id\":42,\"label\":\"Monument historique\"}],\"website\":\"http://www.aubenas.fr\",\"phone\":\"04 75 87 81 11\",\"links\":[],\"access\":{\"fr\":\"Accès piéton, ou navette gratuite centre historique. Nombre de visiteurs simultanés limité à 25 personnes.\",\"it\":\"pedestrianized Accesso o spola(navetta) libera(gratuita) centro storico. Il numero di visitatori simultanei ha limitato a 25 persone.\",\"es\":\"Acceso peatón, o naveta gratuita centra histórico(a). Número de visitantes simultáneos limitado a 25 personas.\",\"de\":\"Fußgängerzugang oder flankt kostenloser Pendelzug historisch zur Mitte. Zahl(Anzahl) von gleichzeitigen Besuchern, die mit 25 Personen begrenzt ist.\",\"en\":\"pedestrianized Access, or free shuttle historic centre. Number of simultaneous visitors limited to 25 people.\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null}', '2016-03-16 10:09:13', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07200', NULL, 25221, '07019'),
(834688, 'maison-michel-veyrenc657_5033_5563_8809_14370_20060', 'Maison Michel Veyrenc', '8, rue Jourdan, 07200 Aubenas, Ardèche, Auvergne-Rhône-Alpes', 'Aubenas', 'FR', '44.620937', '4.389057', NULL, '2019-04-29 15:39:12', '2019-04-29 15:39:12', 0, 71987906, '{\"image\":null,\"description\":{\"fr\":\"Construite sur les vestiges du Château-vieux d\'Aubenas, la Maison Michel Veyrenc  entre dans l\'histoire en 1593 avec l\'arrestation des bienheureux jésuites Jacques Salès et Guillaume Sautemouche, reconnus au rang des martyrs par l’Eglise catholique. Elle sera fortement endommagée lors de la révolte de Roure en 1670. C\'est vers 1740 que François-Louis Barthélémy, avocat, fait construire son escalier. Son fils sera premier consul d\'Aubenas en 1789. En plus de l\'escalier, remarquable par sa stéréotomie et ses rampes en fer forgé de style rocaille, on peut remarquer dans la cour d’entrée et les rez-de-chaussée des vestiges de l\'époque médiévale et le système d\'alimentation de la citerne en eaux pluviales. On relève aussi les restes d’une grande et ancienne cuisine et une halle autrefois ouverte. En façade sur la rue Jourdan, la grande porte d’entrée à bosses date du XVIIIe siècle, et à l’opposé, au nord, la cour charretière conserve aussi des vestiges du Château-vieux ; la façade arrière du logis avec sa fenêtre à meneaux et les corbeaux en balcon qui supportaient les lieux d’aisance remonte au XVIIe.\",\"en\":\"Built on the vestiges of the Castle-old man of Aubenas, the House Michel Veyrenc enters the history books in 1593 with the arrest of the happy Jesuits Jacques Salès and Guillaume Sautemouche, recognised at the rank of the martyrs by the catholic Church. It will be strongly harmed during the revolt of Roure in 1670\\\\. It is by 1740 when François-Louis Barthélémy, lawyer(avocado), makes build its staircase. His son will be first consul of Aubenas in 1789\\\\. Besides the staircase, remarkable for its stéréotomie and its wrought iron banisters of rocaille style, it is possible to point out in the court(yard) of entrance(entry) and the ground floors of the vestiges of medieval time(period) and system of food(supply) of the tank in rainwaters. The rests of an old(former) big(great) and cooking(kitchen) and a hall(market) in the past open are also raised(found). In facade on the street Jourdan, the big(great) front-door with bumps dates the XVIIIth century, and in opposite, in North, the carter court(yard) also keeps(preserves) vestiges of the Castle-old man; the facade defers the ravens of the home with its two-light frame and in balcony who supported(bore) the places of ease go back up(raise) to the XVIIth century.\",\"de\":\"Auf den Spuren des Schlosses - gebaut, Aubenas Alt, das Haus geht Michel Veyrenc 1593 mit der Verhaftung der glücklichen Jesuiten Jacques Salès und Guillaume Sautemouche in die Geschichte ein, die an der Reihe der Märtyrer von der katholischen Kirche erkannt sind. Sie wird bei der Revolte von Roure 1670 stark beschädigt werden. Eben gegen 1740 baut sich François - Louis Barthélémy, Rechtsanwalt, seine Treppe. Sein Sohn wird der erste Konsul von Aubenas 1789 sein. Zusätzlich zur Treppe, die von seinem Stéréotomie und seinen eisernen Geländern(Rampen) bemerkenswert ist, die durch Rokokostil geschmiedet(gebildet) ist, kann man im Eingangshof und den Erdgeschossen der Spuren der mittelalterlichen Epoche und des Versorgungssystems der Zisterne in Regenwasser bemerken. Man hebt auch die Reste einer großen und ehemaligen Küche und einer früher geöffneten Markthalle auf. In der Fassade auf der Straße Jourdan datiert die große Eingangstür in Beulen das XVIII. Jahrhundert und im Gegenübergestellten, im Norden, dem charretière Hof behält auch Spuren des Schlosses - Alt; die Fassade schiebt die Behausung mit ihrem Fenster in Fensterpfosten und den Raben im Balkon auf, die die Gewandtheitsorte stützten, gehe auf das XVII. Jahrhundert zurück.\",\"es\":\"Construyendo sobre los vestigios del Castillo - Viejo de Aubenas, la Casa Michel Veyrenc entra en la historia en 1593 con la detención de los jesuitas bienaventurados Jacques Salès y Guillaume Sautemouche, reconocidos al nivel de los mártires por la Iglesia católica. Será fuertemente dañada en el momento de la rebelión de Roure en 1670\\\\. Es hacia 1740 cuando François-luis Barthélémy, abogado, hace construir su escalera. Su hijo será el primer cónsul de Aubenas en 1789\\\\. Además de la escalera, notable por su stéréotomie y sus rampas de hierro forjada de estilo grutesco, podemos observar en el patio de entrada y los pisos bajos de los vestigios de la época medieval y el sistema de alimentación de la cisterna de aguas pluviales. Levantamos también los restos de una gran y antigua cocina y un mercado en otro tiempo abierto. En fachada sobre la calle Jourdan, la gran puerta de entrada a jorobas fecha siglo XVIII, y al contrario, en el norte, el patio charretière conserva también vestigios del Castillo - Viejo; la fachada atrasa la vivienda con su ventana a cruceros y los cuervos en balcón que sostenían los lugares de holgura sube al siglo XVII.\",\"it\":\"Aggiunto accanto ai vestigi dell\'uomo vecchio dal Castello di Aubenas, la Casa Michel Veyrenc entra nei libri di storia nel 1593 con l\'arresto dei Gesuiti felici Jacques Salès e Guillaume Sautemouche, riconosciuto al grado(posizione) dei martiri dalla chiesa cattolica. Sarà fortemente nociuto durante la rivolta di Roure nel 1670\\\\. È per il 1740 quando François-Louis Barthélémy, l\'avvocato (l\'avocado), fa costruiscono la sua scala. Suo figlio sarà il primo console di Aubenas nel 1789\\\\. Oltre alla scala, notevole per il suo stéréotomie e la sua ringhiera di ferro battuto di stile(classe) di rocaille, è possibile indicare nella corte (l\'iarda(il cortile)) d\'entrata(d\'ammissione) (l\'entrata(ingresso)) e i pianterreni dei vestigi di tempo medievale (il periodo) e il sistema del cibo (la fornitura(provvista)) del serbatoio(carro armato) in acque piovane. I riposi del grande (vecchio) precedente e il cocente (la cucina) e una sala (il mercato) nel passato aperto sono anche alzati (trovati). In facciata sulla via Jourdan, la porta d\'ingresso grande con colpi esce con il secolo XVIIIth, e in contrario, in Nord, la corte di carrettiere (l\'iarda(il cortile)) anche tiene (mantiene(conserva)) vestigi dell\'uomo vecchio dal Castello; la facciata differisce i corvi della casa con la sua struttura(cornice) di due luci e in balcone chi ha sostenuto ha (portato) i posti(luoghi) di disinvoltura ritornano su (alzano) al secolo XVIIth. Zona di\"},\"tags\":[{\"id\":2,\"label\":\"Château, hôtel urbain, palais, manoir\"},{\"id\":42,\"label\":\"Monument historique\"}],\"website\":\"http://www.facebook.com/MaisonVeyrencDeLaValette?hc_location=timeline\",\"phone\":null,\"links\":[],\"access\":{\"fr\":\"Zone piétone proche du château.\",\"en\":\"Zone piétone close to the castle.\",\"de\":\"Zone piétone, die Schloss nahe.\",\"es\":\"Zona piétone próximo(a) al castillo.\",\"it\":\"piétone vicino al castello.\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null}', '2016-03-16 10:09:17', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07200', NULL, 25221, '07019'),
(834715, 'eglise-romane657_5033_5563_8809_14370_20060', 'Eglise romane', 'Le village, 07120 Balazuc', 'Balazuc', 'FR', '44.509473', '4.372172', NULL, '2019-04-29 15:39:28', '2019-04-29 15:39:28', 0, 52237967, '{\"image\":null,\"description\":{\"fr\":\"Eglise romane du XIe siècle restaurée en 2007.\"},\"tags\":[{\"id\":3,\"label\":\"Édifice religieux\"}],\"phone\":null,\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\"}', '2016-03-16 10:38:34', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07120', NULL, 25221, '07023'),
(834780, 'commanderie-de-jales_5033_5563_8809_14370_20060', 'Commanderie de Jalès', 'Hameau de Jalès, 07460 Berrias-et-Casteljau, Ardèche, Auvergne-Rhône-Alpes', 'Berrias-et-Casteljau', 'FR', '44.369573', '4.222069', NULL, '2019-04-29 15:40:05', '2019-08-19 09:48:47', 0, 95794332, '{\"image\":null,\"description\":{\"fr\":\"Commanderie de templiers construite en 1140, fortifiée durant la guerre 100 ans puis restaurée et agrandie au milieu du XVIIIe siècle.\",\"it\":\"Commanderie di templari costruì nel 1140, rafforzato durante la guerra 100 anni allora restaurati ed estesi nel mezzo del secolo XVIIIth. VIA di\",\"es\":\"Commanderie de templarios construidos en 1140, fortificados durante la guerra 100 años luego restaurada y agrandada en medio del siglo XVIII.\",\"de\":\"Komturei von Templern, die 1140 gebaut, während des Krieges 100 Jahre gestärkt ist, dann, der restauriert und in der Mitte des XVIII. Jahrhunderts vergrößert ist.\",\"en\":\"Commanderie of templars built in 1140, strengthened during the war 100 years then restored and extended in the middle of the XVIIIth century.\"},\"tags\":[{\"id\":3,\"label\":\"Édifice religieux\"},{\"id\":4,\"label\":\"Édifice hospitalier\"},{\"id\":42,\"label\":\"Monument historique\"}],\"website\":\"http://www.berrias-et-casteljau.fr\",\"email\":null,\"phone\":\"04 75 39 30 05\",\"links\":[],\"access\":{\"fr\":\"RD 104\",\"it\":\"104\",\"es\":\"RD 104\",\"de\":\"RD 104\",\"en\":\"RD 104\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null,\"extId\":null}', '2016-03-16 11:14:27', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07460', NULL, 25221, '07031'),
(834791, 'place-de-leglise35_5033_5563_8809_14370_20060', 'Place de l\'église', 'Au sommet du village, 07440 Boffres', 'Boffres', 'FR', '44.921000', '4.703240', NULL, '2019-04-29 15:40:11', '2019-04-29 15:40:11', 0, 34066464, '{\"tags\":[{\"id\":2,\"label\":\"Château, hôtel urbain, palais, manoir\"},{\"id\":3,\"label\":\"Édifice religieux\"}],\"phone\":\"0475583389\",\"access\":{\"fr\":\"parking à proximité\"},\"timezone\":\"Europe/Paris\"}', '2016-03-16 11:34:40', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07440', '508325f8ffffd3600c01af47089b7359', 25221, '07035'),
(834794, 'gare-de-boucieu-le-roi9_5033_5563_8809_14370_20060', 'Gare de Boucieu-le-Roi', '07270 Boucieu-le-Roi, Ardèche, Auvergne-Rhône-Alpes', 'Boucieu-le-Roi', 'FR', '45.035679', '4.681939', NULL, '2019-04-29 15:40:13', '2019-06-03 13:51:32', 0, 80921636, '{\"image\":\"location35133411.jpg\",\"description\":{\"fr\":\"Présentation de matériel ferroviaire à voie métrique restauré ou en cours de restauration dont du matériel classé Monument Historique :\\n- Voitures voyageurs;\\n- Wagons de marchandises;\\n- Matériel de manœuvre et de chantier;\\n-Locomotives à vapeur;\\n- Présentation d’un chantier de pose de voie : outils, principes ;\\n- Qu’est ce qu’une machine à vapeur : de la théorie à la pratique;\\n- Le principe d’une plaque à wagon;\\n- Historique de la ligne CFD Tournon - Lamastre.\",\"en\":\"Presentation(Display) of railroad material(equipment) with metric way restored or in the course of restoration(catering) of which of the material(equipment) classified as \\\"Historic Monument\\\":\\n*   Cars travellers;\\n*   Railroad freight cars;\\n*   Material(Equipment) of laborer(operation) and of construction site(work); - stream locomotives;\\n*   Presentation(Display) of a construction site(work) of pose(installation) of way: tools, principles;\\n*   What a steam engine: of theory in practice;\\n*   The principle of a plate(patch) with car;\\n*   History of the line CFD Tournon - Lamastre.\",\"de\":\"Präsentation des Eisenbahnmaterials in metrischem Weg, das restauriert ist oder im Laufe Restaurierung, von der des geordneten Materials Denkmal:\\n*   Autos Reisende;\\n*   Güterwagen;\\n*   Material des Manövers und Baustelle; - Dampflokomotiven;\\n*   Präsentation einer Baustelle des Anbringens(Körperhaltung) des Weges: Werkzeuge, Prinzipien;\\n*   Dass ist, dass eine Dampfmaschine: der Theorie in der Praxis;\\n*   Das Prinzip einer Platte mit Wagen;\\n*   Geschichte der Linie CFD Tournon - der Lamastre.\",\"es\":\"Presentación de material ferroviario a vía métrica restaurado o en curso de restauración de la que material clasificado Monumento Histórico:\\n*   Coches viajeros;\\n*   Vagones de mercancías;\\n*   Material de obrero(maniobra) y de obra; - locomotoras de vapor;\\n*   Presentación de una obra de postura(colocación) de vía: herramientas, principios;\\n*   Que es lo que una máquina de vapor: de la teoría a la práctica;\\n*   El principio de una placa a vagón;\\n*   Reseña histórica de la línea CFD Tournon - Lamastre.\",\"it\":\"Presentazione (Esposizione(Dimostrazione)) di materiale di ferrovia (attrezzatura) con strada(mezzo) metrica restaurata o nel corso di restauro(restituzione) (servizio di approvvigionamento) di cui del materiale (attrezzatura) classificato come \\\"Monumento Storico\\\":\\n*   Viaggiatori(Viaggiatori di commercio) d\'auto;\\n*   Carri merci di ferrovia;\\n*   Materiale (Attrezzatura) di manovale (operazione(azione)) e di cantiere edile (lavoro(opera)); - locomotive di corrente(fiume);\\n*   Presentazione (Esposizione(Dimostrazione)) di un cantiere edile (lavoro(opera)) di posa (insediamento(installazione)) di strada(mezzo): strumenti, principi;\\n*   Quale macchina a vapore: di teoria praticamente;\\n*   Il principio di un piatto(placca) (toppa(macchia)) con auto;\\n*   Storia della linea CFD Tournon - Lamastre.\"},\"tags\":[{\"id\":8,\"label\":\"Édifice industriel, scientifique et technique\"}],\"website\":\"http://www.train-du-vivarais.com\",\"email\":null,\"phone\":null,\"links\":[\"https://www.facebook.com/Association.SGVA\"],\"access\":{\"fr\":\"Par la D209\",\"en\":\"By D209\",\"de\":\"Von D209\",\"es\":\"Por D209\",\"it\":\"Da D209\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null,\"extId\":null}', '2016-03-16 11:50:35', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07270', NULL, 25221, '07040'),
(834795, 'village-de-boucieu-le-roi452_5033_5563_8809_14370_20060', 'Village', '07270 Boucieu-le-Roi', 'Boucieu-le-Roi', 'FR', '45.036774', '4.682477', NULL, '2019-04-29 15:40:13', '2019-04-29 15:40:13', 0, 1908877, '{\"image\":\"location19258433.jpg\",\"description\":{\"fr\":\"Boucieu-le-Roi est l\'ancienne capitale du Haut-Vivarais. Son baillage et sa charte de franchise ont permis aux habitants de s\'enrichir et de construire de belles demeures encore visibles aujourd\'hui.\",\"en\":\"Boucieu-le-Roi is the old(former) capital of Haut-Vivarais. His(Her,Its) baillage and his(her,its) charter of franchise(frankness) allowed to the inhabitants to grow rich and to build beautiful still visible(obvious) houses today.\",\"de\":\"Boucieu-Le-Roi ist die ehemalige Hauptstadt von Haut-Vivarais. Sein Baillage und seine Charta des Freimutes haben den Einwohnern ermöglicht, reich zu werden und schöne noch sichtbare Wohnsitze heute zu bauen.\",\"es\":\"Boucieu-le-Roi es la antigua capital de Haut-Vivarais. Su baillage y su carta de franquicia(franqueza) les permitieron a los habitantes enriquecerse y construir bellas moradas todavía visibles hoy.\",\"it\":\"Il Boucieu-le-Roi è antica capitale (vecchia) di Haut-Vivarais. Il suo (Lei, Il suo) baillage e il suo (lei, il suo) lo statuto(il noleggio) di franchigia (la franchezza) permessa agli abitanti di crescere ricco e costruire bello le case (ovvie) ancora visibili(evidenti) oggi.\"},\"tags\":[{\"id\":3,\"label\":\"Édifice religieux\"},{\"id\":8,\"label\":\"Édifice industriel, scientifique et technique\"},{\"id\":42,\"label\":\"Monument historique\"}],\"website\":\"http://www.boucieuleroi.com\",\"phone\":\"04 75 08 10 23\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null}', '2016-03-16 11:50:40', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07270', NULL, 25221, '07040'),
(834830, 'palais-des-eveques_5033_5563_8809_14370_20060', 'Palais des evêques', '16, rue Poterne, 07700 Bourg-Saint-Andéol', 'Bourg-Saint-Andéol', 'FR', '44.373200', '4.647160', NULL, '2019-04-29 15:40:33', '2019-04-29 15:40:33', 0, 95155140, '{\"image\":\"location6396618.jpg\",\"description\":{\"fr\":\"Fort médiéval embelli au XVe et XVIIe siècles, le palais épiscopal de Bourg St Andéol est un des monuments les plus complexes du Vivarais. Ses points forts: les cuisines et salle des banquets du XVe siècle, les plafonds à la française peints au XVIIe siècle (1638) et dans la chapelle le musée René Margotton, peintre contemporain.\"},\"tags\":[{\"id\":2,\"label\":\"Château, hôtel urbain, palais, manoir\"},{\"id\":13,\"label\":\"Lieu de pouvoir, édifice judiciaire\"},{\"id\":15,\"label\":\"Musée, salle d\'exposition\"},{\"id\":36,\"label\":\"Villes et Pays d\'art et d\'histoire\"},{\"id\":38,\"label\":\"Jardin remarquable\"},{\"id\":42,\"label\":\"Monument historique\"}],\"website\":\"http://www.palais-des-eveques.fr\",\"phone\":\"04 75 54 41 76\",\"access\":{\"fr\":\"Stationnement sur les quais du Rhône, au pied du Palais\"},\"timezone\":\"Europe/Paris\"}', '2016-03-16 12:01:09', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07700', 'JEP-LIEU160838', 25221, '07042'),
(835018, 'prieure-saint-felix_5033_5563_8809_14370_20060', 'Prieuré Saint-Félix', 'Lieu-dit Saint-Félix, 07240 Châteauneuf-de-Vernoux', 'Châteauneuf-de-Vernoux', 'FR', '44.921937', '4.641308', NULL, '2019-04-29 15:42:24', '2019-04-29 15:42:23', 0, 95301591, '{\"image\":null,\"description\":{\"fr\":\"Le prieuré Saint-Félix est un ensemble de bâtiments (premières mentions au XIIIe siècle) comprenant une chapelle de style gothique qui daterait de 1511, une église à nef unique construite vers 1670 (dont la cloche serait l\'une des plus vieilles du Vivarais), et une maison du prieur construite vers 1780.\",\"en\":\"The priory Saint Félix is a building complex (first mentions(grades) in the XIIIth century) understanding a chapel of Gothic style which would date of 1511, a church with unique(only) nave built by 1670 (the bell of which would be one of oldest of Vivarais), and a house of the prior was built by 1780.\",\"de\":\"Das Priorat Saint-Félix ist eine Reihe von Gebäuden (die ersten Erwähnungen im XIII. Jahrhundert) eine Kapelle gotischen Stiles enthaltend, der 1511, eine Kirche in einzigem(einzigartigem) Schiff veraltet wäre, die gegen 1670 gebaut ist (deren Glocke eine der Ältesten von Vivarais wäre) und ein Haus des Priors, das gegen 1780 gebaut ist.\",\"es\":\"El prieuré Saint-Félix es un conjunto de edificios (las primeras menciones en el siglo XIII) que comprende una capilla de estilo gótico que dataría de 1511, una iglesia a nave única construida hacia 1670 (cuya campana sería una de las más viejas de Vivarais), y una casa del prior construida hacia 1780.\",\"it\":\"Il Santo di monastero retto da priore Félix è un complesso d\'edificio(di costruzione) (le prime menzioni (i gradi(le classi)) nel secolo XIIIth) la comprensione di una cappella di stile(classe) gotico che risalirebbe del 1511, una chiesa con unico (solo) la navata costruita per il 1670 (il campanello(campana) di cui sarebbe uno di più vecchi di Vivarais), e una casa del precedente fu costruita per il 1780.\"},\"tags\":[{\"id\":3,\"label\":\"Édifice religieux\"}],\"phone\":\"04 75 58 18 10\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null}', '2016-03-16 13:34:21', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07240', NULL, 25221, '07060'),
(835063, 'local-saga707_5033_5563_8809_14370_20060', 'Local de la SAGA', 'Route de Privas, 07210 Chomérac, Ardèche, Auvergne-Rhône-Alpes', 'Chomérac', 'FR', '44.706787', '4.656688', NULL, '2019-04-29 15:42:52', '2019-04-29 15:42:52', 0, 69741770, '{\"image\":\"location325946.jpg\",\"description\":{\"fr\":\"Local où sont entreposés plus de 2000 fac-similés de registres paroissiaux de l\'Ardèche du XVIe siècle au début du XIXe siècle. Ces registres sont tous munis d\'une table alphabétique qui facilite grandement la recherche généalogique. Vous pourrez ainsi très simplement reconstituer le\\\"patrimoine caché\\\" de votre famille.\",\"it\":\"Il locale (il Posto(Luogo)) dove sono immagazzinati più che facsimile del 2000 di registri parrocchiali di Ardèche del secolo XVIth all\'inizio del secolo XIXth. Questi registri tutti sono forniti un tavolo(tabella) alfabetico che fa la ricerca genealogica (la ricerca) più facile molto. Sarà capace così molto semplicemente di ricostruire la \\\"eredità (le tenute(proprietà)) nascoste\\\" alla Sua famiglia.\",\"es\":\"Local donde son almacenados más de 2000 facsímiles de registros parroquiales del Ardèche du XVIe el siglo al principio del siglo XIX. Estos registros todos son proveídos de una mesa alfabética que facilita ampliamente la búsqueda(investigación) genealógica. Usted podrá reconstituir tan muy simplemente el \\\"patrimonio escondido\\\" a su familia.\",\"de\":\"Lokal, wo mehr als 2000 Faksimiles der Kirchenbücher des Ardèche du XVIe Jahrhundert an Anfang des XIX. Jahrhunderts eingelagert werden. Diese Register alle werden mit einer alphabetisch geordneten Liste ausgestattet, die sehr die genealogische Suche(Forschung) erleichtert. Sie können so sehr einfach das \\\"\\\" Ihrer Familie versteckte Erbe wieder herstellen.\",\"en\":\"Premises(Place) where are stored more than 2000 facsimiles of parish registers of the Ardèche of the XVIth century at the beginning of the XIXth century. These registers all are provided with an alphabetic table which makes genealogical research(search) easier greatly. You will be able so very simply to reconstruct the \\\"heritage hidden\\\" from your family.\"},\"tags\":[{\"id\":7,\"label\":\"Archives\"}],\"website\":\"http://www.geneardeche.org/\",\"phone\":\"0475648413\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"© Hubert Dallard\"}', '2016-03-16 13:53:51', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07210', NULL, 25221, '07066'),
(835142, 'le-barrage-de-clauzel-et-le-canal-des-allemands105_5033_5563_8809_14370_20060', 'Le barrage de clauzel et le canal des allemands', 'Place du Village, 07410 Colombier-le-Vieux', 'Colombier-le-Vieux', 'FR', '45.036974', '4.652376', NULL, '2019-04-29 15:43:37', '2019-04-29 15:43:37', 0, 26985556, '{\"description\":{\"fr\":\"Nous vous invitons à découvrir ce patrimoine industriel et historique de la moyenne vallée du Doux, à sa confluence avec la Daronne. Un lieu imprégné d\'Histoire locale du 19° au 21° siècle.\"},\"tags\":[{\"id\":8,\"label\":\"Édifice industriel, scientifique et technique\"},{\"id\":11,\"label\":\"Espace naturel, parc, jardin\"}],\"timezone\":\"Europe/Paris\"}', '2016-03-16 14:10:15', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07410', '9adff1a5ffffd360014d626f82e9b4e8', 25221, '07069'),
(835144, 'les-gorges-de-la-daronne565_5033_5563_8809_14370_20060', 'Les gorges de la daronne', 'Place du Village, 07410 Colombier-le-Vieux', 'Colombier-le-Vieux', 'FR', '45.036974', '4.652376', NULL, '2019-04-29 15:43:38', '2019-04-29 15:43:38', 0, 44156797, '{\"image\":\"location89758967.jpg\",\"description\":{\"fr\":\"Nous vous invitons à découvrir un endroit hors du commun, les Gorges de la Daronne, au cœur de l\'Espace Naturel Sensible des 3 D : Doux, Duzon, Daronne. Tout au long du sentier d\'interprétation, vous pourrez apprécier le charme de ce lieu enchanteur, randonner dans une nature préservée et vous laisser happer par ce lieu marqué par l\'Histoire des hommes. Une découverte tout en douceur, imprégnée de respect.\"},\"tags\":[{\"id\":11,\"label\":\"Espace naturel, parc, jardin\"}],\"timezone\":\"Europe/Paris\"}', '2016-03-16 14:10:20', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07410', '9ae0f362ffffd360014d626f2c6f3709', 25221, '07069'),
(835174, 'eglise-de-lubilhac830_5033_5563_8809_14370_20060', 'Église de Lubilhac', 'Lieu-dit « Lubilhac », 07000 Coux, Ardèche, Auvergne-Rhône-Alpes', 'Coux', 'FR', '44.732873', '4.620118', NULL, '2019-04-29 15:43:56', '2019-06-03 12:30:37', 0, 84914996, '{\"image\":\"location25300774.jpg\",\"description\":{},\"tags\":[{\"id\":3,\"label\":\"Édifice religieux\"},{\"id\":42,\"label\":\"Monument historique\"}],\"email\":null,\"phone\":null,\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null,\"extId\":null}', '2016-03-16 14:30:13', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07000', NULL, 25221, '07072'),
(835199, 'le-barrage-de-la-palisse248_5033_5563_8809_14370_20060', 'Le barrage de la palisse', 'La Palisse, Cros-de-Géorand, 07510', 'Cros-de-Géorand', 'FR', '44.870589', '4.180002', NULL, '2019-04-29 15:44:10', '2019-04-29 15:44:10', 0, 23085587, '{\"image\":\"location285017.jpg\",\"description\":{\"fr\":\"Patrimoine contemporain de la montagne ardéchoise, le barrage de la Palisse, le pont suspendu et son histoire Venez découvrir le village de La Palisse, son histoire au pied des vestiges du  château des seigneurs de Géorand à la construction du barrage et du pont suspendu et les énergies renouvelables du XXI° siècle.\"},\"tags\":[{\"id\":8,\"label\":\"Édifice industriel, scientifique et technique\"}],\"website\":\"http://ardeche-sources-loire.com/\",\"timezone\":\"Europe/Paris\"}', '2016-03-16 14:36:46', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07630', '56359646ffffd3605cf2c5808d1ee3c4', 25221, '07026');
INSERT INTO `location` (`id`, `slug`, `placename`, `address`, `city`, `country`, `latitude`, `longitude`, `owner_id`, `created_at`, `updated_at`, `main`, `uid`, `store`, `processed_at`, `department`, `region`, `city_district`, `postal_code`, `eve_id`, `agenda_id`, `insee`) VALUES
(835200, 'abbatiale-sainte-marie158_5033_5563_8809_14370_20060', 'Abbatiale Sainte-Marie', 'Avenue Joliot-Curie, 07350 Cruas, Ardèche, Auvergne-Rhône-Alpes', 'Cruas', 'FR', '44.656667', '4.763978', NULL, '2019-04-29 15:44:10', '2019-07-17 09:34:40', 0, 72970419, '{\"image\":\"location73423064.jpg\",\"description\":{\"fr\":\"Cette abbatiale romane est le seul vestige d’une abbaye puissante fondée en 804. Les bâtiments conventuels ont été détruits une première fois pendant la guerre de cent ans et une seconde fois pendant les guerres de religion au XIVe siècle. Le site sur lequel est construite l’abbatiale est occupé par l’homme au minimum depuis le 1er siècle de notre ère. Lors des fouilles entreprises en 1972, ont été retrouvées des fondations d’une villa gallo-romaine du IIIe ou IVe siècle. A la fin du Ve siècle, le site est consacré à la religion, avec la construction du premier édifice paléochrétien à abside orientée qui reprend en partie les murs de la villa gallo-romaine. Dès lors plusieurs édifices religieux vont se succéder. L’abbatiale, telle que nous la connaissons aujourd’hui, a été exposée dès sa construction aux crues du ruisseau de Crûle qui a apporté des alluvions qui ont obstrué l’intérieur et l’extérieur du bâtiment. C’est  Prosper Mérimée, alors inspecteur des Monuments Historiques qui est à l’initiative de son classement monument historique. En 1972, Robert Saint-Jean, maître de conférences à l\'université Paul-Valéry de Montpellier, effectue une campagne de recherches archéologiques. Puis entre 1982 et 1990, à la demande de la DRAC Rhône-Alpes, les recherches archéologiques reprennent, avec le réaménagement du parvis et la mise au jour de la nécropole. En 1998/1999, Francesco Flavigny, architecte en chef des monuments historiques, réaménage le chevet de l\'abbatiale. Les fouilles précitées ont permis de déblayer afin que l’abbatiale retrouve son aspect d’origine. Des trésors ont été ainsi mis à jour : la tribune monastique (12è s.) qui marquait la séparation entre les moines et le peuple. Deux seulement existent de nos jours : celle de Cruas et celle de Serrabonne dans les Pyrénées Orientales. En 1983, lorsque la tribune a été dégagée de son carcan de pierres et de boues, elle était dans un état de conservation exceptionnel. Les 13 chapiteaux sons tous différents, il y a même un visage humain. La crypte est la partie la plus ancienne : elle abritait les reliques de Saint Torquat et Saint Josserand et compte un magnifique bestiaire. L’église haute compte des trompe-l’œil, des restes de fresques, une table d’autel du XIè et surtout une mosaïque du XIIe représentant Elie et Henoc, seul vestige restant sur l’ensemble de mosaïques qui commémoraient le passage à Cruas du pape Urbain II en 1095.\",\"it\":\"Questa chiesa d\'abbazia Romanza è l\'unico vestigio di un\'Abbazia potente basata (istituito) in 804\\\\. Gli edifici(costruzione) conventual (le navi) furono distrutti una prima volta durante Centinaio della guerra d\'anni e una seconda volta durante le guerre di religione nel secolo XIVth. Il sito in cui è costruito la chiesa d\'abbazia è occupato dall\'uomo a minimo per il 1o secolo della nostra era. Durante ricerche (gli scavi) cominciati (intrapreso) nel 1972, furono trovati delle fondazioni(fondamenti) di una villa Gallo-romana dell\'IIIth o il secolo IVth. Alla fine di secolo Ve, il sito è dedicato a religione, con la costruzione del primo primo edificio cristiano con abside orientata che i curriculum vitae (restituisce) parzialmente le pareti della villa Gallo-romana. Da allora in poi parecchi edifici(costruzione) religiosi stanno per seguire l\'un l\'altro. La chiesa d\'abbazia, come noi lo sanno(conoscono) oggi, è stato esposto (spiegato) dalla sua costruzione alle inondazioni della corrente(fiume) di Crûle che ha portato l\'alluvione che ha ostruito l\'interno e l\'esterno (l\'aspetto) dell\'edificio(costruzione) (la nave). È Prosper Mérimée, l\'architetto allora principale(capo) dei monumenti Storici che è per l\'iniziativa della sua classificazione (che considera) il monumento antico. Nel 1972, Robert Saint Jean, il conferenziere all\'università Paul-Valéry di Montpellier, fa una campagna (la campagna) di ricerche archeologiche (le ricerche). Allora tra il 1982 e il 1990, su richiesta di DRAC Rhône-Alpes, le ricerche archeologiche (le ricerche) cominciano di nuovo, con la riparazione (la riorganizzazione) del quadrato(piazza) e il portare a luce della necropoli. In 1998/1999, Francesco Flavigny, l\'architetto principale(capo) di monumenti storici, ricostruisce il bedhead della chiesa d\'abbazia. Le ricerche summenzionate (gli scavi) hanno permesso di portare via in modo che la chiesa d\'abbazia trovi il suo aspetto d\'origine. I tesori sono stati così aggiornati: il forum(foro) monastico (stand(chiosco)) (12è s.) chi (che) ha segnato(macchiato) la separazione(l\'interruzione del rapporto di lavoro) tra i monaci e la gente. Due solo esistono al momento: questo di Cruas e quello di Serrabonne nel Pyrénées-Orientales (Pirenei Orientali). Nel 1983, quando il forum(foro) (lo stand(il chiosco)) fu sgomberato (rilasciato) del suo giogo(sprone) di pietre e di fanghi, lei fu in uno stato eccezionale di conservazione. 13 capitali (i tendoni da circo) suonano un po\' diverse, c\'è perfino una faccia umana. La cripta è la parte più vecchia (il partito): lei ha riparato il retaggio del santo Torquat e il santo Josserand e conta un bestiario splendido(eccellente). La chiesa alta conta addobbi di vetrine(arti di presentare una situazione sotto una luce favorevole), i riposi d\'affreschi, il tavolo(la tabella) d\'altare di XIÈ e particolarmente a mosaico del rappresentante XIIth Elie e Henoc, solo il vestigio che rimane sulla serie(set) (il gruppo) di mosaici che hanno commemorato il passaggio(brano) in Cruas del papa Urbain II in 1095.\",\"es\":\"Esta iglesia abacial romance es el solo vestigio de uno Abadía poderosa fundada en 804\\\\. Los edificios conventuales han sido destruidos la primera vez durante la guerra de ciento años y una segunda vez durante las guerras de religión en el siglo XIV. El sitio sobre el cual es construida la iglesia abacial está ocupado por el hombre por lo menos desde el siglo 1 de nuestra era. En el momento de los registros(excavaciones) emprendidos en 1972, han sido reencontradas fundaciones de una quinta gallo-romana del IIIo o IVo siglo. Al fin de Ve siglo, el sitio es consagrado a la religión, con la construcción del primer edificio paléochrétien a ábside orientado que recupera en parte las paredes de la quinta gallo-romana. Desde entonces varios edificios religiosos van a sucederse. La iglesia abacial, tal como nosotras la conocemos hoy, ha sido expuesta desde su construcción a las crecidas del arroyo de Crûle que aportó aluviones que obstruyeron el interior y el exterior del edificio. Está Prosper Mérimée, entonces arquitecto en jefe de los Monumentos Históricos quien es a instancias de su clasificación monumento histórico. En 1972, Robert santo-Jean, maestro de conferencias en la universidad Paul-Valéry de Montpellier, efectúa un campo(campaña) de búsquedas(investigaciones) arqueológicas. Luego entre 1982 y 1990, a petición de DRAC Rhône-Alpes, las búsquedas(investigaciones) arqueológicas prosiguen, con el reajuste de la plaza y la postura al día de la necrópolis. En 1998/1999, Francesco Flavigny, arquitecto en jefe de los monumentos históricos, reordena la cabecera de la iglesia abacial. Los registros(excavaciones) precitados permitieron desmontar con el fin de que la iglesia abacial reencuentre su aspecto de origen. Tesoros tan han sido actualizados: la tribuna monástica (12o(a) s.) que marcaba la separación entre los monjes y el pueblo. Dos solamente existen en nuestros días: Cruas y el de Serrabonne en las Pyrénées Orientales. En 1983, cuando la tribuna ha sido soltada(desempeñada) su picota de piedras y de lodos, ella estaba en un estado excepcional de conservación. Los 13 capiteles sonidos todo diferente, hasta hay una cara humana. La cripta es la parte más antigua: ella abrigaba las reliquias de santo Torquat y santo Josserand y cuenta un bestiario magnífico. La alta iglesia cuenta de engáñala ojo, restos de frescos, una mesa de altar del siglo XI y sobre todo un mosaico del XIIo representante Elie y Henoc, solo vestigio que quédese en conjunto de mosaicos que conmemoraban el paso a Cruas del papa Urbain II en 1095.\",\"de\":\"Dieser ist Abtsromanische die einzige Spur einer mächtigen(starken) 804 gegründeten Abtei. Die klösterlichen Gebäude sind das erste Mal während des Hundertjährigen Krieges und das zweite Mal während der Religionskriege im XIV. Jahrhundert zerstört worden. Die Website(Stätte), auf der der Abts-gebaut wird, wird vom Menschen(Mann) mindestens seit dem 1\\\\. Jahrhundert unserer Ära eingenommen(beschäftigt). Bei den 1972 untergenommenen(beeinflussten) Ausgrabungen(Durchsuchungen) sind durch Gründungen(Stiftungen) einer gallo-römischen Villa des III. oder IV. Jahrhunderts wiedergefunden worden. Am Ende Ve Jahrhundert wird die Website(Stätte) der Religion, mit dem Bau des ersten Bauwerkes gewidmet, der in der gesteuerten(ausgerichteten) Apsis ist paléochrétien, die die Wände der gallo-römischen Villa teilweise wieder nimmt. Sobald werden mehrere religiöse Bauwerke folgen. Der Abts-, solche wie wir kennen sie heute, ist seit ihrem Bau dem Hochwasser des Baches von Crûle ausgesetzt worden, der Alluvions gebracht hat, die das Innere und die Außenseite des Gebäudes versperrt haben. Eben Prosper Mérimée, dann der Chefarchitekt der Historischen Denkmäler ist auf Initiative seiner Unterschutzstellung(Einordnens) Denkmal. 1972 führt Robert Heiliger - Jean, der außerordentliche Professor an der Universität Paul-Valéry von Montpellier, ein Land(Kampagne) archäologischer Suchen(Forschungen) aus. Dann zwischen 1982 und 1990, auf Antrag DRAC Rhône-Alpes, kommen(beginnen) die archäologischen Suchen(Forschungen), mit der Neuausstattung(Sanierung) des Kirchenvorplatzes und der ans Tageslicht Gebrachten der Nekropolis wieder auf(wieder). In 1998/1999 gestaltet Francesco Flavigny, Chefarchitekt der historischen Denkmäler, das Kopfende des Abts-neu. Die oben genannten Ausgrabungen(Durchsuchungen) haben ermöglicht, frei zu machen, damit der Abts-seinen Ursprungsanblick(Ursprungsgesichtspunkt) wiederfindet. Schätze sind auf den neuesten Stand gebracht worden: die klösterliche Tribüne (12è s.) der die Trennung unter den Mönchen und dem Volk markierte. Zwei nur existieren in unseren Tagen: derjenige von Cruas und derjenige von Serrabonne in den Pyrénées Orientales. 1983, wenn die Tribüne von ihrem Halseisen der Steine und von den Schlammen befreit worden ist, war sie in einem außergewöhnlichen Erhaltungszustand(Erhaltungsstaat). Die 13 Kapitelle Töne alle Verschiedenen, es gibt ein menschliches Gesicht sogar. Die Krypta ist der älteste Teil(Seite): Sie schützte die Reliquien von Torquat und Josserand und rechnet ein herrliches Tierbuch. Die hohe Kirche zählt, täusche sie Auge, Reste der Fresken, Altarplatte von XIè und vor allem Mosaik des XII. Vertreters Elie und Henoc, der einzigen auf der Mosaikgesamtheit(Mosaikkomplex) bleibenden Spur, die des Vorübergehens(Passage) in Cruas des Papstes Urbain II 1095 gedachten.\",\"en\":\"This Romance abbey church is the only vestige of a powerful Abbey based(established) in 804\\\\. The conventual buildings(ships) were destroyed a first time during Hundred Years\' War and a second time during the wars of religion in the XIVth century. The site on which is built the abbey church is occupied by the man to minimum for the 1st century of our era. During excavations(searches) begun(undertaken) in 1972, were found of the foundations of a Gallo-Roman villa of the IIIth or IVth century. At the end of Ve century, the site is devoted to religion, with the construction of the first early Christian building with orientated apse which resumes(takes back) partly the walls of the Gallo-Roman villa. From then on several religious buildings are going to follow one another. The abbey church, such as us know it today, was exposed(explained) from its construction to the floods of the stream of Crûle which brought alluvium which obstructed the inside and the outside(exterior) of the building(ship). It is Prosper Mérimée, then chief architect of the Historic monuments who is on the initiative of his classification(ranking) historical monument. In 1972, Robert Saint Jean, lecturer at the university Paul-Valéry of Montpellier, makes a campaign(countryside) of archaeological researches(searches). Then between 1982 and 1990, at the request of DRAC Rhône-Alpes, archaeological researches(searches) start again, with the refitting(reorganisation) of the square and the bringing to light of the necropolis. In 1998/1999, Francesco Flavigny, chief architect of historic monuments, redevelops the bedhead of the abbey church. Aforementioned excavations(searches) allowed to clear away so that the abbey church finds its aspect of origin. Treasures were so updated: the monastic forum(stand) (12è s.) who(which) marked separation between the monks and the people. Two only exist at present: that of Cruas and that of Serrabonne in the Pyrénées-Orientales. In 1983, when the forum(stand) was brought out(loosened) of its yoke of stones and of muds, she(it) was in an exceptional state of preservation. 13 capitals(big tops) sounds any different, there is even a human face. The crypt is the most old(former) part(party): she(it) sheltered the relics of saint Torquat and saint Josserand and counts a splendid bestiary. The high church counts window dressings, rests of frescoes, table of altar of XIÈ and especially mosaic of the XIIth representative Elie and Henoc, only vestige staying on the set(group) of mosaics which memorialised passage in Cruas of the pope Urbain II in 1095.\"},\"tags\":[{\"id\":3,\"label\":\"Édifice religieux\"},{\"id\":16,\"label\":\"Site archéologique\"},{\"id\":42,\"label\":\"Monument historique\"},{\"id\":36,\"label\":\"Villes et Pays d\'art et d\'histoire\"}],\"website\":\"http://www.sud-ardeche-tourisme.com/\",\"email\":null,\"phone\":\"04 75 49 59 20\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"© Abbatiale Sainte-Marie\",\"extId\":null}', '2016-03-16 14:37:40', 'Un nom de département', 'Un nom de région', NULL, '07350', NULL, 25221, '07076'),
(835242, 'atelier-de-sabotier262_5033_5563_8809_14370_20060', 'Atelier de sabotier', 'Rue du château, 07570 Désaignes', 'Désaignes', 'FR', '44.994474', '4.516937', NULL, '2019-04-29 15:44:36', '2019-04-29 15:44:36', 0, 89634707, '{\"image\":\"location75514424.jpg\",\"description\":{},\"tags\":[{\"id\":15,\"label\":\"Musée, salle d\'exposition\"}],\"website\":\"http://www.desaignes.fr\",\"phone\":\"04 75 06 66 21\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null}', '2016-03-16 14:48:19', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07570', NULL, 25221, '07079'),
(835244, 'caveau-de-degustation_5033_5563_8809_14370_20060', 'Caveau de dégustation', 'Château de Désaignes rue du Chateau, 07570 Désaignes', 'Désaignes', 'FR', '44.994500', '4.517130', NULL, '2019-04-29 15:44:37', '2019-04-29 15:44:37', 0, 27354966, '{\"image\":\"location72530911.jpg\",\"description\":{\"fr\":\"Le caveau, installé dans les caves du château de Désaignes, propose de découvrir la richesse des productions locales, dont le picodon et la châtaigne. Un sommelier initiera le public aux accords entre mets et vins.\"},\"tags\":[{\"id\":2,\"label\":\"Château, hôtel urbain, palais, manoir\"}],\"website\":\"http://www.desaignes.fr\",\"phone\":\"04 75 06 61 19\",\"access\":{\"fr\":\"D 534 - D 533\"},\"timezone\":\"Europe/Paris\"}', '2016-03-16 14:48:23', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07570', 'JEP-LIEU163302', 25221, '07079'),
(835246, 'temple-et-orgues-du-temple217_5033_5563_8809_14370_20060', 'Temple et orgues du temple', 'Rue du temple, 07570 Désaignes', 'Désaignes', 'FR', '44.994190', '4.517230', NULL, '2019-04-29 15:44:39', '2019-04-29 15:44:39', 0, 21278658, '{\"image\":\"location74199810.jpg\",\"description\":{\"fr\":\"Le Temple date de 1823 et est construit sur une forteresse du XIIe siècle. Il possède deux orgues qui font l\'objet de la visite.\"},\"tags\":[{\"id\":3,\"label\":\"Édifice religieux\"}],\"website\":\"http://www.desaignes.fr\",\"phone\":\"04 75 06 66 21\",\"access\":{\"fr\":\"D533 puis D534\"},\"timezone\":\"Europe/Paris\"}', '2016-03-16 14:48:32', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07570', 'JEP-LIEU168217', 25221, '07079'),
(835312, 'chateau-et-jardins-du-pin_5033_5563_8809_14370_20060', 'Château et jardins du Pin', 'Le Pin, 07380 Fabras, Ardèche, Auvergne-Rhône-Alpes', 'Fabras', 'FR', '44.651373', '4.292277', NULL, '2019-04-29 15:45:22', '2019-04-29 15:45:22', 0, 78941912, '{\"image\":\"location63596368.jpg\",\"description\":{\"fr\":\"Maison forte typique de la Cévenne ardéchoise possédant un ameublement ancien ainsi qu\'une collection d\'art contemporain. Elle est environnée de jardins contemporains labellisés \\\"Jardin remarquable\\\" alliant sculptures et végétaux.\",\"it\":\"Casa forte(solida) tipica di Ardèche Cévenne che possiede i mobili (vecchi) precedenti così come una raccolta(collezione) d\'arte contemporanea. È circondato da giardini contemporanei autenticati(garantiti) \\\"il Giardino notevole\\\" le sculture leganti e i vegetali(le verdure).\",\"es\":\"Casa fuerte típica de Cévenne ardéchoise que posee un antiguo mueblaje así como una colección de arte contemporáneo. Es rodeada de jardines contemporáneos labellisés \\\" Jardín notable \\\" aliando esculturas y vegetales.\",\"de\":\"Typisches starkes Haus von Cévenne ardéchoise, das alte Möbel besitzt sowie Sammlung zeitgenössischer Kunst. Sie wird von zeitgenössischen Skulpturen und Pflanzen verbindenden Gärten mit Gütezeichen \\\" bemerkenswerter Garten \\\" umgeben.\",\"en\":\"Strong house typical of Ardèche Cévenne possessing an old(former) furniture as well as a collection of contemporary art. It is surrounded with certified contemporary gardens \\\" remarkable Garden \\\" alloying sculptures and vegetables.\"},\"tags\":[{\"id\":2,\"label\":\"Château, hôtel urbain, palais, manoir\"},{\"id\":11,\"label\":\"Espace naturel, parc, jardin\"},{\"id\":15,\"label\":\"Musée, salle d\'exposition\"},{\"id\":38,\"label\":\"Jardin remarquable\"}],\"website\":\"http://www.chateaudupin.org\",\"phone\":\"04 75 38 05 26\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null}', '2016-03-16 15:30:04', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07380', NULL, 25221, '07087'),
