(835490, 'parc-naturel-regional-des-monts-dardeche_5033_5563_8809_14370_20060', 'Parc naturel regional des Monts d\'Ardèche', 'Maison du Parc Domaine de Rochemure, 07380 Jaujac, Ardèche, Auvergne-Rhône-Alpes', 'Jaujac', 'FR', '44.636377', '4.262270', NULL, '2019-04-29 15:47:26', '2019-04-29 15:47:26', 0, 42668000, '{\"image\":\"location84804107.jpg\",\"description\":{\"fr\":\"La Maison du Parc est située au cœur du domaine de Rochemure au pied du dernier volcan éteint du Vivarais. Un parcours d\'interprétation \\\"La coulée vive\\\" permet de découvrir le domaine tout au long de l\'année, en accès libre. Le sentier curieux chemine sur le domaine, de surprise en surprise, dans les pas du jardinier de Rochemure. Suivez le fil rouge, il vous révèlera le secret du domaine !\"},\"tags\":[{\"id\":2,\"label\":\"Château, hôtel urbain, palais, manoir\"},{\"id\":9,\"label\":\"Édifice rural\"},{\"id\":11,\"label\":\"Espace naturel, parc, jardin\"}],\"website\":\"http://www.parc-monts-ardeche.fr\",\"phone\":\"04 75 36 38 60\",\"links\":[],\"access\":{\"fr\":\"Accès fléché dans le village, parking, chemin piéton sur 300 mètres.\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null}', '2016-03-16 16:54:57', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07380', NULL, 25221, '07107'),
(835491, 'chateau983_5033_5563_8809_14370_20060', 'Château', 'Le village, 07110 Joannas', 'Joannas', 'FR', '44.565277', '4.251747', NULL, '2019-04-29 15:47:27', '2019-04-29 15:47:27', 0, 9716161, '{\"description\":{\"fr\":\"Grande bâtisse de plan carré présentant des éléments médiévaux et agrandie à la Renaissance.\"},\"tags\":[{\"id\":2,\"label\":\"Château, hôtel urbain, palais, manoir\"},{\"id\":3,\"label\":\"Édifice religieux\"}],\"timezone\":\"Europe/Paris\"}', '2016-03-16 16:55:39', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07110', 'JEP-LIEU160659', 25221, '07109'),
