(835594, 'eglise-de-macheville393_5033_5563_8809_14370_20060', 'Eglise de macheville', 'Macheville, 07270 Lamastre', 'Lamastre', 'FR', '44.985480', '4.584690', NULL, '2019-04-29 15:48:36', '2019-04-29 15:48:36', 0, 13176332, '{\"description\":{\"fr\":\"Eglise d\'origine romane à l\'architecture composite. Edifiée dès le 10e siècle et agrandie ensuite par les moines bénédictins. Elle est dédiée à St Domnin, jeune martyr de l’époque romaine. A l’intérieur, dix chapiteaux, que l’on peut dater du XI° siècle. L\'intérieur vient d\'être restauré.\"},\"tags\":[{\"id\":3,\"label\":\"Édifice religieux\"}],\"timezone\":\"Europe/Paris\"}', '2016-03-16 17:49:18', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07270', '55eb0278ffffd3605cf2c580510badd0', 25221, '07129'),
(835595, 'parcours-lamastre-en-lumiere_5033_5563_8809_14370_20060', 'Parcours \"lamastre en lumière\"', 'Place Montgolfier, 07270 Lamastre', 'Lamastre', 'FR', '44.985807', '4.579688', NULL, '2019-04-29 15:48:37', '2019-04-29 15:48:37', 0, 30399923, '{\"description\":{\"fr\":\"Le parcours vous propose une découverte originale de la ville, s\'amuse à vous étonner et vous révèle au détour de ses rues et ruelles la richesse de son patrimoine.\"},\"tags\":[{\"id\":3,\"label\":\"Édifice religieux\"},{\"id\":11,\"label\":\"Espace naturel, parc, jardin\"}],\"website\":\"http://www.lamastre.fr\",\"phone\":\"04 75 06 48 99\",\"links\":[\"https://www.facebook.com/pages/Pays-de-Lamastre/156172707814139?ref=hl\"],\"timezone\":\"Europe/Paris\"}', '2016-03-16 17:49:23', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07270', '55ed7be2ffffd3605cf2c580b67a8230', 25221, '07129'),
