(837111, 'ancienne-eglise-st-jean-baptiste_8809_14370_20060', 'Ancienne église Saint-Jean-Baptiste', 'Place de la vieille église, 07400 Meysse, Ardèche, Auvergne-Rhône-Alpes', 'Meysse', 'FR', '44.609817', '4.721058', NULL, '2019-04-29 16:06:55', '2019-07-17 09:38:10', 0, 78489988, '{\"image\":null,\"description\":{\"fr\":\"La vieille église abrite un baptistère paléochrétien (Haut Moyen Âge Ve siècle).\",\"en\":\"The old church shelters an early Christian baptistry (High Middle Ages Ve century).\",\"de\":\"Die alte Kirche schützt eine paléochrétien Taufkapelle (frühes Mittelalter Ve Jahrhundert).\",\"es\":\"La vieja iglesia abriega un baptisterio paléochrétien (Alta Edad media Ve el siglo).\",\"it\":\"La chiesa vecchia ripara un primo battistero cristiano (Le Mezze età alte il secolo di Ve). il Parcheggio di\"},\"tags\":[{\"id\":3,\"label\":\"Édifice religieux\"},{\"id\":42,\"label\":\"Monument historique\"},{\"id\":15,\"label\":\"Musée, salle d\'exposition\"},{\"id\":36,\"label\":\"Villes et Pays d\'art et d\'histoire\"}],\"website\":\"http://www.meysse.fr\",\"email\":null,\"phone\":\"04 75 52 96 21\",\"links\":[\"https://fr-fr.facebook.com/Vivre-%C3%A0-Meysse-1601371270181800/\"],\"access\":{\"fr\":\"Parking place de la mairie puis cheminement piétonnier.\",\"en\":\"Parking lot places from the city council then pedestrianized progression.\",\"de\":\"Parkplatz stellt(bringt unter) das Rathaus dann das Fußgängervorwärtsgehen.\",\"es\":\"Aparcamiento de coches coloca el ayuntamiento luego el progreso peatonal.\",\"it\":\"mette dal consiglio comunale allora pedestrianized l\'avanzamento.\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null,\"extId\":null}', '2016-05-20 08:18:18', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07400', NULL, 25221, '07157'),
(837136, 'temple-protestant-312-avenue-clemenceau-07500-guilherand-granges_8809_14370_20060', 'Temple protestant', '312 avenue Clémenceau, 07500 Guilherand-Granges, Ardèche, Auvergne-Rhône-Alpes', 'Guilherand-Granges', 'FR', '44.932187', '4.874468', NULL, '2019-04-29 16:07:13', '2019-04-29 16:07:13', 0, 68728760, '{\"image\":null,\"description\":{\"fr\":\"Temple protestant à l\'architecture du XXe siècle alliant béton armé et grande baie vitrée avec piscine baptismale pour les baptêmes d\'adulte.\",\"en\":\"Temple protesting in the architecture of the XXth century alloying armed concrete and big(great) plate glass window with baptismal swimming pool for adult\'s baptisms.\",\"de\":\"In der Architektur des XX. Jahrhunderts beteuernder Tempel, der Stahlbeton und die große mit Taufschwimmbad für die Taufen von Erwachsenem(Erwachsener) verglasene Bucht(Glasfenster) verbindet.\",\"es\":\"Templo que protesta a la arquitectura del siglo XX que alía hormigón armar y gran ventanal con piscina bautismal para los bautismos de adulto.\",\"it\":\"Il tempio(La tempia) che protesta nell\'architettura del secolo XXth che si lega ha armato la finestra di vetro piano concreta e grande di piscina battesimale per i battesimi d\'adulto.\"},\"tags\":[{\"id\":3,\"label\":\"Édifice religieux\"}],\"phone\":\"0475444036\",\"links\":[],\"access\":{\"fr\":\"gratuit\",\"en\":\"free\",\"de\":\"kostenlos\",\"es\":\"gratuito\",\"it\":\"libero(gratuito)\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null}', '2016-05-21 12:54:17', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07500', NULL, 25221, '07102'),
