(837592, 'foret-des-chambons-et-du-tanargue_8809_14370_20060', 'Forêt des Chambons et du Tanargue', 'Station de la Croix de Bauzon', 'Borne', 'FR', '44.629473', '4.089367', NULL, '2019-04-29 16:12:22', '2019-04-29 16:12:22', 0, 4357301, '{\"image\":\"location79093752.jpg\",\"description\":{\"fr\":\"La visite se déroulera avec Daniel MICHAUD, ancien agent de l\'ONF et amateur éclairé de la faune et la flore du Tanargue. Il vous présentera les richesses de la forêt.\"},\"tags\":[{\"id\":3,\"label\":\"Édifice religieux\"}],\"website\":\"http://www.ardeche-otcevenneetmontagne.com\",\"phone\":\"04 66 46 65 36\",\"links\":[],\"access\":{\"fr\":\"Route\"},\"state\":1,\"timezone\":\"Europe/Paris\"}', '2016-05-31 14:07:42', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07590', '508a9e17ffffd3600c01af479338fc1b', 25221, '07038'),
