(837817, 'portail-buis_8809_14370_20060', 'Portail Buis', '241 route de Buis', 'Cour-et-Buis', 'FR', '45.361477', '4.751708', NULL, '2019-04-29 16:14:58', '2019-04-29 16:14:58', 0, 94949053, '{\"image\":null,\"description\":{\"fr\":\"Surmonté d’une génoise à cinq rangs en tuiles canal, en molasse, clef saillante datée de 1725, impostes moulurées, chasse-roues.\"},\"tags\":[],\"phone\":null,\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\"}', '2016-05-31 17:02:34', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07340', 'ef5cf413ffffffce0114eb0b0e96a3a8', 25221, '07143'),
(837844, 'orgue-de-leglise_8809_14370_20060', 'Orgue de l\'église', 'Vidalon', 'Davézieux', 'FR', '45.254174', '4.681877', NULL, '2019-04-29 16:15:23', '2019-04-29 16:15:23', 0, 97301143, '{\"image\":\"location85941175.jpg\",\"description\":{\"fr\":\"Ancienne chapelle des Papeteries Canson et Montgolfier, l\'église de Vidalon, de style néo-gothique, abrite un orgue de François Callinet remonté par Cavaillé-Coll en 1880.\"},\"tags\":[{\"id\":3,\"label\":\"Édifice religieux\"},{\"id\":42,\"label\":\"Monument historique\"}],\"phone\":null,\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\"}', '2016-05-31 17:22:34', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07430', '2e74bb72ffffd36063feec6468a67557', 25221, '07078'),
(837882, 'musee-des-ornements-de-la-femme_8809_14370_20060', 'Musée des ornements de la femme', 'Chemin de Letieux', 'Faucigny', 'FR', '45.136374', '4.702118', NULL, '2019-04-29 16:15:56', '2019-04-29 16:15:56', 0, 41731470, '{\"image\":null,\"description\":{\"fr\":\"Voyage dans le temps au travers de la mode. Le musée expose une collection renouvelée chaque année: Dentelles rares, merveilleux éventails et somptueuses robes ainsi qu\'un grand nombre d\'étonnants éventails. Accessoires de mode du XVIIIe siècle à 1930. Histoire de la dentelle et des dentellières.\"},\"tags\":[],\"website\":\"http://www.museedelafemme.fr\",\"phone\":\"04 50 03 90 37\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\"}', '2016-05-31 18:20:42', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07290', 'JEP-LIEU163155', 25221, '07250'),
(837883, 'prieure836_8809_14370_20060', 'Prieuré', 'La Charrière', 'Faugères', 'FR', '44.739773', '4.631978', NULL, '2019-04-29 16:15:57', '2019-04-29 16:15:57', 0, 38725912, '{\"image\":\"location65979796.jpg\",\"description\":{\"fr\":\"Siège d\'une seigneurie monastique durant huit siècles, l\'ensemble église-prieuré constitue le vestige des bâtiments ecclésiaux et castraux créés tout au long du Moyen-Age.\"},\"tags\":[{\"id\":2,\"label\":\"Château, hôtel urbain, palais, manoir\"},{\"id\":3,\"label\":\"Édifice religieux\"}],\"website\":\"http://www.beauzons.com\",\"phone\":\"04 75 39 48 07\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\"}', '2016-05-31 18:20:59', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07000', '51cef546ffffffce0149f87913f79396', 25221, '07088'),
(837926, 'eglise498_8809_14370_20060', 'Eglise', '07140 Gravières', 'Gravières', 'FR', '44.420841', '4.091620', NULL, '2019-04-29 16:16:30', '2019-04-29 16:16:30', 0, 9955517, '{\"image\":null,\"description\":{\"fr\":\"Eglise romane du XIIe siècle avec des ajouts  gothiques des XIVe et XVIe siècles. Elle renferme un retable du XIVe siècle \\\"Arbre de Jessé\\\".\",\"it\":\"Chiesa romanza del secolo XIIth con aggiunte gotiche dello XIVth e secoli XVIth. Lei contiene un ritavolo(ritabella) del secolo XIVth \\\"L\'albero(Il tendiscarpe) di Jessé\\\".\",\"es\":\"Iglesia romance del siglo XII con añadidos góticos de los XIVos y XVIos siglos. Ella cierra un retable del siglo XIV \\\"Árbol de Jessé\\\".\",\"de\":\"Romanische Kirche des XII. Jahrhunderts mit gotischen Zusätzen die XIV. und XVI. Jahrhunderte. Sie enthält einen Retable des XIV. Jahrhunderts \\\"Baum von Jessé\\\".\",\"en\":\"Romance church of the XIIth century with Gothic additions of the XIVth and XVIth centuries. She(It) contains a retable of the XIVth century \\\"Tree of Jessé\\\".\"},\"tags\":[{\"id\":3,\"label\":\"Édifice religieux\"},{\"id\":42,\"label\":\"Monument historique\"}],\"phone\":\"04 75 37 31 07\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null}', '2016-05-31 19:18:54', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07140', NULL, 25221, '07100'),
