(838067, 'eglise467_8809_14370_20060', 'Eglise', 'rue Saint-Paul Joyeuse', 'Joyeuse', 'FR', '44.479729', '4.239597', NULL, '2019-04-29 16:18:11', '2019-04-29 16:18:11', 0, 98394655, '{\"image\":null,\"description\":{},\"tags\":[{\"id\":3,\"label\":\"Édifice religieux\"}],\"website\":\"http://arej.free.fr\",\"phone\":\"04 75 36 65 83\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null,\"extId\":null}', '2016-06-10 09:49:20', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07260', NULL, 25221, '07110'),
(838106, 'tour-des-comtes-de-geneve47_8809_14370_20060', 'Tour des Comtes de Genève', 'Place Saint-François', 'La Roche-sur-Foron', 'FR', '45.241917', '4.673328', NULL, '2019-04-29 16:18:40', '2019-04-29 16:18:40', 0, 68007153, '{\"image\":\"location63474730.jpg\",\"description\":{\"fr\":\"Dernier vestige de la forteresse des Comtes de Genève, la tour est juchée sur un bloc de \\\"roche\\\" et domine les berges de la rivière \\\"le Foron\\\", ce qui explique probablement l\'origine du nom de la ville. On atteint son sommet après avoir traversé les \\\"grottes\\\" des instituteurs et des capucins, puis visité la salle des archers. Le belvédère offre alors un panorama splendide du Lac Léman, du Jura Suisse, de nos montagnes proches et bien évidemment de la cité médiévale.\"},\"tags\":[{\"id\":2,\"label\":\"Château, hôtel urbain, palais, manoir\"}],\"website\":\"http://www.larochesurforon.com\",\"phone\":\"04 50 03 36 68\",\"links\":[\"http://www.facebook.com/otlarochesurforon\",\"http://twitter.com/OTLaRocheForon\"],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\"}', '2016-06-10 10:20:05', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07100', '6c8fe612ffffd3604c62f7efded190eb', 25221, '07010'),
(838129, 'ancienne-usine-de-soie-du-moulinet280_8809_14370_20060', 'Ancienne Usine de Soie du Moulinet', 'Route de Valgorge', 'Largentière', 'FR', '44.488647', '4.229727', NULL, '2019-04-29 16:18:57', '2019-04-29 16:18:57', 0, 86798402, '{\"image\":null,\"description\":{\"fr\":\"Visite guidée des anciennes salles de travail, vêtements anciens, panneaux sur les industries locales.\"},\"tags\":[{\"id\":8,\"label\":\"Édifice industriel, scientifique et technique\"}],\"phone\":null,\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\"}', '2016-06-10 10:50:19', 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07260', '55f027d7ffffd3605cf2c5806c8ee7e3', 25221, '07132');
