(839601, 'chateau-des-roure_14370_20060', 'Château des Roure', '07150 Labastide de Virac', 'Labastide-de-Virac', 'FR', '44.351073', '4.402437', NULL, '2019-04-29 16:37:30', '2019-04-29 16:37:30', 0, 26618240, '{\"image\":null,\"description\":{\"fr\":\"Château des XIVème, XVème et XVIème siècles.\",\"en\":\"Castle of the XIVth, XVth and XVIth centuries.\",\"de\":\"Schloss die XIV., XV. und XVI. Jahrhunderte.\",\"es\":\"Castillo de los XIVos, XVos y XVIos siglos.\",\"it\":\"Castello dello XIVth, XVth e secoli XVIth.\"},\"tags\":[{\"id\":42,\"label\":\"Monument historique\"},{\"id\":2,\"label\":\"Château, hôtel urbain, palais, manoir\"}],\"phone\":null,\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07150', NULL, 25221, '07113'),
(839602, '07150-labastide-de-virac206_14370_20060', 'Labastide de Virac', '07150 Virac', 'Labastide-de-Virac', 'FR', '44.351073', '4.402437', NULL, '2019-04-29 16:37:31', '2019-07-16 13:20:21', 0, 30196279, '{\"image\":null,\"description\":{\"fr\":\"hameau du village\",\"en\":\"hamlet of the village\",\"de\":\"Weiler des Dorfes\",\"es\":\"caserío del pueblo\",\"it\":\"piccolo villaggio del villaggio\"},\"tags\":[{\"id\":16,\"label\":\"Site archéologique\"}],\"email\":null,\"phone\":\"0687087358\",\"links\":[],\"access\":{\"fr\":\"en voiture ou à pied\",\"en\":\"by car or on foot\",\"de\":\"mit dem Auto oder zu Fuß\",\"es\":\"en coche o a pie\",\"it\":\"in macchina o a piedi\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null,\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07150', NULL, 25221, '07113'),
(839603, 'baume-doulen133_14370_20060', 'Baume d\'Oulen', '07150 Labastide de Virac', 'Labastide-de-Virac', 'FR', '44.351073', '4.402437', NULL, '2019-04-29 16:37:32', '2019-04-29 16:37:32', 0, 46544736, '{\"image\":null,\"description\":{\"fr\":\"Baume à rejoindre par un dénivelé important.\\nEn surplomb des gorges de l\'Ardèche.\",\"en\":\"Balm to be joined by an important difference in altitude. Pendent of gorges(breasts) of the Ardèche.\",\"de\":\"Dem sich von einem wichtigen Höhenunterschied anzuschließenden Balsam. Der Hälse von Ardèche überhängend.\",\"es\":\"Bálsamo que hay que reunir por uno desnivelado importando. En desplome de las gargantas de Ardèche.\",\"it\":\"Il balsamo da essersi unito da una differenza importante d\'altitudine. Sospeso di gole (i petti(seni)) di Ardèche.\"},\"tags\":[{\"id\":16,\"label\":\"Site archéologique\"}],\"phone\":\"0628828680\",\"links\":[],\"access\":{\"fr\":\"Covoiturage en voiture 4x4 sur pistes DFCI.\",\"en\":\"Ride sharing by car 4x4 on tracks(runways) DFCI.\",\"de\":\"Covoiturage mit dem Auto 4x4 auf Spuren DFCI.\",\"es\":\"Covoiturage en coche 4x4 sobre pistas DFCI.\",\"it\":\"Giro che condivide in macchina 4x4 su tracce(sentieri) (piste di decollo) DFCI.\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07150', NULL, 25221, '07113'),
(839612, 'pavillon-de-jardin_14370_20060', 'Pavillon de jardin', '77 chemin de Paurière 07220 Viviers', 'Viviers', 'FR', '44.492556', '4.678652', NULL, '2019-04-29 16:37:37', '2019-04-30 10:32:34', 0, 4529146, '{\"image\":\"location75953046.jpg\",\"description\":{\"fr\":\"Pavillon de jardin 1900\",\"en\":\"Garden house 1900\",\"de\":\"Gartenpavillon 1900\",\"es\":\"Pabellón de jardín 1900\",\"it\":\"Casa di giardino il 1900\"},\"tags\":[{\"id\":9,\"label\":\"Édifice rural\"},{\"id\":11,\"label\":\"Espace naturel, parc, jardin\"}],\"website\":\"https://dartagnans.fr/fr/projects/restauration-de-peintures-murales-viviers-07/campaign\",\"phone\":null,\"links\":[\"https://www.youtube.com/watch?v=RX8I0STEo1M\",\"http://www.culture.gouv.fr/documentation/memoire/HTML/IVR82/ia00047881/index.htm\",\"http://www.culture.gouv.fr/documentation/memoire/HTML/IVR82/im07000592/index.htm\"],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"F. Greffe\",\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07220', NULL, 25221, '07346'),
(839627, 'jardin-la-terre-pimprenelle990_14370_20060', 'Jardin La Terre Pimprenelle', 'La Terre Pimprenelle Alboussière 07440', 'Alboussière', 'FR', '44.959174', '4.711977', NULL, '2019-04-29 16:37:47', '2019-04-29 16:37:47', 0, 4002428, '{\"image\":\"location9449667.jpg\",\"description\":{\"fr\":\"Le jardin a une superficie d\'un hectare, avec plus de 1200 arbres et arbustes dont 600 variétés différentes. Il est structuré sur le nombre d\'or (ellipses, spirales, suites, triangles...).\\nLe nombre des éléments (arbres, arbustes, vivaces, pierres...) fait référence à la suite de Fibonacci, \\nle but étant de créer un espace harmonieux d\'énergies positives.\\nLe minéral et le végétal entretiennent des liens très étroits : le minéral raconte l\'histoire de la terre, le végétal s\'en nourrit.\"},\"tags\":[{\"id\":38,\"label\":\"Jardin remarquable\"}],\"website\":\"https://sites.google.com/site/jardinlaterrepimprenelle/home\",\"phone\":\"0475580027\",\"links\":[\"https://www.tripadvisor.fr/Attraction_Review-g2266836-d9721974-Reviews-Jardin_La_Terre_Pimprenelle-Alboussiere_Ardeche_Auvergne_Rhone_Alpes.html\",\"https://www.facebook.com/Jardin-La-Terre-Pimprenelle-Alboussière-Ardèche-1705871403013532/\"],\"access\":{\"fr\":\"entrée payante\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null}', NULL, NULL, NULL, NULL, '07440', NULL, 25221, NULL),
