(840370, 'commanderie-de-devesset_20060', 'Commanderie de Devesset', '07320 Devesset', 'Devesset', 'FR', '45.069160', '4.387430', NULL, '2019-04-29 16:48:01', '2019-08-19 13:52:29', 0, 85972641, '{\"image\":\"location75325967.jpg\",\"description\":{\"fr\":\"Château de Devesset, ancienne Commanderie de l\'Ordre des Templiers, Monument Historique depuis 1980.\",\"en\":\"Castle of Devesset, old(former) Commanderie in the order of the Templars, Historical monument since 1980.\",\"it\":\"Castello di Devesset, ex Commanderie (vecchio) nell\'ordine dei Templari, monumento Antico dal 1980.\",\"es\":\"Castillo de Devesset, antigua Commanderie del orden de los Templarios, Monumento Histórico desde el 1980.\",\"de\":\"Schloss von Devesset, ehemalige Komturei in der Größenordnung von den Templern, Denkmal seit 1980.\"},\"tags\":[{\"id\":42,\"label\":\"Monument historique\"},{\"id\":2,\"label\":\"Château, hôtel urbain, palais, manoir\"},{\"id\":4,\"label\":\"Édifice hospitalier\"},{\"id\":6,\"label\":\"Édifice militaire, enceinte urbaine\"},{\"id\":9,\"label\":\"Édifice rural\"},{\"id\":13,\"label\":\"Lieu de pouvoir, édifice judiciaire\"}],\"email\":null,\"phone\":\"06 33 52 71 83\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"© Association pour le patrimoine du plateau Vivarais-Lignon\",\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, NULL, NULL, 25221, '07080'),
