(883500, 'chateau-de-verchaus', 'Château de Verchaüs', '2823 RD 86 - 07220 Viviers', 'Viviers', 'FR', '44.510126', '4.680471', NULL, '2019-05-10 08:21:41', '2019-07-17 09:43:41', 0, 95102555, '{\"image\":\"location95102555.jpg\",\"description\":{\"fr\":\"Situé à Viviers, en Ardèche, le château de Verchaüs (CCV) est un lieu de création artistique pluridisciplinaire et mutualisé, orienté autour de trois domaines artistiques : l’art contemporain, les métiers d’art et le spectacle vivant.\"},\"tags\":[{\"id\":2,\"label\":\"Château, hôtel urbain, palais, manoir\"},{\"id\":36,\"label\":\"Villes et Pays d\'art et d\'histoire\"}],\"website\":\"http://chateaudeverchaus.com/\",\"email\":\"contact@chateaudeverchaus.com\",\"phone\":\"04 75 50 61 79\",\"links\":[\"https://www.facebook.com/collectifchateaudeverchaus/\"],\"access\":{\"fr\":\"Parking\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"© Collectif du château de Verchaüs\",\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, NULL, NULL, 25221, '07346'),
