(884287, 'musee-du-vivarais-protestant-maison-de-pierre-et-marie-durand', 'Musée du Vivarais protestant - Maison de Pierre et Marie Durand', '555 chemin du Bouschet, Le Bouschet de Pranles, 07000 Pranles', 'Pranles', 'FR', '44.772054', '4.574547', NULL, '2019-05-13 16:42:46', '2019-07-05 13:20:29', 0, 60430771, '{\"image\":\"location60430771.jpg\",\"description\":{\"fr\":\"Maison natale de Pierre et Marie Durand, martyres de la répression contre les protestants au 18ème siècle. Elle a été aménagée en musée du protestantisme.\"},\"tags\":[{\"id\":42,\"label\":\"Monument historique\"},{\"id\":9,\"label\":\"Édifice rural\"},{\"id\":12,\"label\":\"Édifice commémoratif\"},{\"id\":15,\"label\":\"Musée, salle d\'exposition\"}],\"website\":\"http://www.museevivaraisprotestant.org\",\"email\":\"museevivarais@orange.fr\",\"phone\":\"04 75 64 22 74\",\"links\":[],\"access\":{\"fr\":\"Accès routier. Parking.\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"© Jean Paul Sarrazin\",\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07000', NULL, 25221, '07184'),
(886050, 'fabrique-du-pont-daleyrac-st-pierreville', 'fabrique du pont d\'aleyrac st pierreville', '379 route du pont d\'aleyrac st pierreville', 'Saint-Pierreville', 'FR', '44.813823', '4.491058', NULL, '2019-05-20 14:59:04', '2019-06-04 14:21:59', 0, 51846371, '{\"image\":null,\"description\":{\"fr\":\"La Fabrique organise depuis 25 ans des expositions artistiques dans un ancien moiulinage...\"},\"tags\":[{\"id\":8,\"label\":\"Édifice industriel, scientifique et technique\"},{\"id\":15,\"label\":\"Musée, salle d\'exposition\"}],\"email\":\"mirabelbe@wanadoo.fr\",\"phone\":\"0673353788\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null,\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07190', NULL, 25221, '07286'),
(886075, 'st-vincent-de-durfort-07360', 'Le Chambon-de-Bavas', 'Le Chambon-de-Bavas 07360 Saint-Vincent-de-Durfort', 'Le Chambon de Bavas', 'FR', '44.786351', '4.621686', NULL, '2019-05-20 15:57:17', '2019-06-03 13:38:51', 0, 1895621, '{\"image\":\"location1895621.jpg\",\"description\":{\"fr\":\"Un hameau historique au cœur même du protestantisme une richesse architecturale à découvrir !\"},\"tags\":[{\"id\":2,\"label\":\"Château, hôtel urbain, palais, manoir\"},{\"id\":9,\"label\":\"Édifice rural\"},{\"id\":11,\"label\":\"Espace naturel, parc, jardin\"},{\"id\":7,\"label\":\"Archives\"}],\"website\":\"http://www.marcheartisanal07.fr\",\"email\":\"map.07360@gmail.com\",\"phone\":\"0682619768\",\"links\":[],\"access\":{\"fr\":\"Desservie par bus de privas ainsi que la vallée de l\'Eyrieux en voiture passage oblige pour rejoindre les vallées de l\'Eyrieux et de l\'Ouvéze\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"© SNLAmap07\",\"extId\":\"L\'histoire d\'une région\"}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07360', NULL, 25221, '07303'),
(889440, 'dolmen-de-la-combe-de-bonne-fille-grospierres', 'Dolmen de la combe de Bonne Fille', 'Parking de la gare, Grospierres', 'Grospierres', 'FR', '44.400202', '4.289532', NULL, '2019-06-04 15:02:49', '2019-07-16 07:34:23', 0, 53377367, '{\"image\":\"location53377367.jpg\",\"description\":{\"fr\":\"Visite d\'un dolmen en cours de fouille.\"},\"tags\":[{\"id\":16,\"label\":\"Site archéologique\"}],\"email\":\"dolmen@cc-gorgesardeche.fr\",\"phone\":\"07 89 00 33 74\",\"links\":[],\"access\":{\"fr\":\"Stationnement en bas du chemin d\'accès mais places limitées. Organistaion d\'un covoiturage au départ du arking de la gare. Montée de 35 min sur chemin accidenté. Une bonne condition physique est nécessaire. Enfant à partir de 5 ans.\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"© Nicolas Lateur\",\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07120', NULL, 25221, '07101'),
(890639, 'chapelle-du-lycee-gabriel-faure-a-tournon-sur-rhone', 'Chapelle du lycée Gabriel Faure', 'Place Stéphane Mallarmé 07300 Tournon-sur-Rhône', 'Tournon-sur-Rhône', 'FR', '45.067288', '4.834425', NULL, '2019-06-09 19:21:38', '2019-06-13 12:01:27', 0, 22241616, '{\"image\":\"location22241616.jpg\",\"description\":{\"fr\":\"1673  Pose de la première pierre. \\n1707  Pose de la balustrade du chœur.\\n1713  Édification du clocher. Comme la chapelle est à peu près terminée, elle est ouverte au culte. \\n1714  Les toiles du Capassin (Jean Capassin, peintre florentin \\ndu 16ème siècle, dont la carrière aurait commencé auprès du célèbre Raphaël, et qui avait été engagé par le cardinal François de Tournon lorsque ce dernier effectuait des missions diplomatiques à Rome pour le compte de François Ier puis d\'Henri II) et les tapisseries (Aubusson et Flandres) sont abritées dans la chapelle, ce qui leur évite de disparaître dans l\'incendie du Collège\\n1720  Les cendres du cardinal François II de Tournon sont déposées derrière l\'autel.\\nRéhabilitation de la Chapelle (organisation de concerts et expositions de sculptures et peintures.\"},\"tags\":[{\"id\":42,\"label\":\"Monument historique\"}],\"website\":\"\",\"email\":\"martinesauvaget@free.fr\",\"phone\":\"+33 (0)4 75 08 43 02\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"Pierre-Marie SAUVAGET\",\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', 'Saint-Jacques', '07300', NULL, 25221, '07324'),
