INSERT INTO `location` (`id`, `slug`, `placename`, `address`, `city`, `country`, `latitude`, `longitude`, `owner_id`, `created_at`, `updated_at`, `main`, `uid`, `store`, `processed_at`, `department`, `region`, `city_district`, `postal_code`, `eve_id`, `agenda_id`, `insee`, `ext_id`) VALUES
(912946, 'coeur-de-ville-dannonay', 'Coeur de ville', '26 rue Franki Kramer 07100 Annonay', 'Annonay', 'FR', '45.240396', '4.668784', NULL, '2019-07-03 16:02:26', '2019-07-04 11:28:30', 0, 14471367, '{\"image\":\"location14471367.jpg\",\"description\":{\"fr\":\"un parcours organisé par le Collectif Centre Ancien, alliant art et patrimoine :\\n. Des artistes et des créatifs amateurs s\'installent au sein de cours privées du Coeur de ville d\'Annonay. Qu’y a-t-il derrière la porte cochère, l’imposte ? Souvent un escalier monumental, parfois un ancien lavoir, un jardin… les expositions et animations vous donneront l\'occasion de découvrir ce patrimoine caché du quartier.\\nsamedi 21 septembre de 10h à 19h \\nRue Franki Kramer - Place Grenette - Place Mayol - Place des Forges - Place Poterne - rue du petit collège - rue des récollets - rue Sainte Marie - chemin de Paras - chemin des Terres .\\nAu 26FK (26 rue Franki Kramer) Buvette et Snacking – midi et soir\\nMusique traditionnelle irlandaise \\\"LES OIGNONS PAUVRES\\\", 11h au 26FK, 14h30 et 18h30 sur la place Mayol\\n20h spectacle place des forges \\\"la belle vie\\\" temps fort quelques p\'arts\"},\"tags\":[{\"id\":1,\"label\":\"Maison, appartement, atelier de personnes célèbres\"}],\"website\":\"http://www.lamoustacheetdesdentelles.blogspot.com\",\"email\":\"moustache.dentelles@gmail.com\",\"phone\":\"0645631299\",\"links\":[\"https://www.facebook.com/pages/Moustache-et-Dentelles/\"],\"access\":{\"fr\":\"Parkings gratuits à proximité - centre ville d\'Annonay\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"Moustache et dentelles (licence libre)\",\"extId\":\"coeurdevilleannonay\"}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', 'L\'Auvergnat', '07100', NULL, 25221, '07010', 'coeurdevilleannonay');
INSERT INTO `location` (`id`, `slug`, `placename`, `address`, `city`, `country`, `latitude`, `longitude`, `owner_id`, `created_at`, `updated_at`, `main`, `uid`, `store`, `processed_at`, `department`, `region`, `city_district`, `postal_code`, `eve_id`, `agenda_id`, `insee`) VALUES
(915097, 'hameau-de-oize-saint-andeol-de-vals', 'Hameau de Oize', '07600 Saint Andéol de Vals', 'Saint-Andéol-de-Vals', 'FR', '44.691848', '4.401808', NULL, '2019-07-08 12:40:19', '2019-07-09 12:17:03', 0, 93729889, '{\"image\":null,\"description\":{},\"tags\":[{\"id\":9,\"label\":\"Édifice rural\"}],\"website\":\"https://www.saint-andeol-de-vals.fr/\",\"email\":null,\"phone\":null,\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null,\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07600', NULL, 25221, '07210'),
(916773, 'mas-daudet810', 'Mas Daudet', '710, Montée de la Vignasse 07120 Saint-Alban-Auriolles', 'Saint-Alban-Auriolles', 'FR', '44.439567', '4.316479', NULL, '2019-07-15 12:34:45', '2019-07-16 14:24:16', 0, 58548672, '{\"image\":\"location58548672.jpg\",\"description\":{\"fr\":\"Le musée : une visite riche et dynamique\\nVisite libre (NL/ALL/GB/FR) ou guidée (FR)\\nVoyagez dans le temps en visitant ce lieu à l\'architecture et aux collections remarquables.\\nDans les caves et la cour de travail revivez les gestes et les savoir-faire de nos anciens (distiller l\'alcool, battre le fer, presser les olives, décortiquer les châtaignes, ...) puis dans la magnanerie vivante pénétrez dans l\'univers du ver à soie, de l’œuf au papillon. Ensuite dans les salons bourgeois, laissez-vous guider par Alphonse Daudet: son écriture fine, sa famille, ses frasques de jeunesse sont autant d\'occasions de découvrir l\'auteur des Lettres de mon Moulin (portraits, correspondances, effets personnels,...).\\nEnquêtes pour les enfants pendant la visite : 3-6ans et 6-11ans (NL/ALL/GB/FR)\"},\"tags\":[{\"id\":41,\"label\":\"Maison des illustres\"},{\"id\":15,\"label\":\"Musée, salle d\'exposition\"}],\"website\":\"http://www.musee-daudet.com\",\"email\":\"musee.daudet@wanadoo.fr\",\"phone\":\"0475396507\",\"links\":[],\"access\":{\"fr\":\"parkings sur place\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"Christian Donin\",\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, NULL, NULL, 25221, '07207'),
(917432, 'satillieu', 'Village', '07290 Satillieu', 'Satillieu', 'FR', '45.150703', '4.614938', NULL, '2019-07-18 10:11:23', '2019-07-18 12:10:58', 0, 78942744, '{\"image\":null,\"description\":{\"fr\":\"Office de tourisme du Val d\'Allée\"},\"tags\":[{\"id\":42,\"label\":\"Monument historique\"},{\"id\":2,\"label\":\"Château, hôtel urbain, palais, manoir\"},{\"id\":3,\"label\":\"Édifice religieux\"}],\"website\":\"http://www.valday-ardeche.com\",\"email\":\"contact@valday-ardeche.com\",\"phone\":\"0631099846\",\"links\":[],\"access\":{\"fr\":\"Parking place de la Faurie\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null,\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07290', NULL, 25221, '07309'),
