(919400, 'moulin-dupuy-a-st-andre-lachamp-lieu-dit-gournier', 'Moulin Dupuy, lieu dit Gournier', '07230 Saint-André-Lachamp', 'Saint-André-Lachamp', 'FR', '44.505506', '4.163402', NULL, '2019-08-05 07:57:44', '2019-08-19 13:40:15', 0, 87632808, '{\"image\":\"location87632808.jpg\",\"description\":{\"fr\":\"Moulin à eau ,datant en 1er lieu du 15é siècle , d\'une dimension peu commune dans les environs et situé dans un écrin de verdure .Actuellement en début de restauration . Le samedi vous pourrez assister aux travaux de rénovation de l\'équipe de bénévoles ; le dimanche une visite extérieure du moulin sera proposée avec son histoire .\"},\"tags\":[{\"id\":9,\"label\":\"Édifice rural\"}],\"website\":\"http://www.moulin-dupuy-1jimdosite.com\",\"email\":\"associationdumoulin.dupuy07@orange.fr\",\"phone\":\"0475395692\",\"links\":[],\"access\":{\"fr\":\"parking obligatoire à 500m\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"© Valérie Immelmann\",\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07230', NULL, 25221, '07213'),
