(920202, 'grange-de-claviere', 'Grange de Clavière', 'Clavière, 07320 Saint-Agrève', NULL, 'FR', '45.017539', '4.407229', NULL, '2019-08-16 11:34:10', '2019-08-19 13:47:34', 0, 56511938, '{\"image\":null,\"description\":{\"fr\":\"La grange de Clavière est l\'une des plus vastes et des plus remarquables des environs de Saint-Agrève. Aménagée, il s\'y déroule des animations musicales chaque année, certaines même à rayonnement international.\"},\"tags\":[{\"id\":9,\"label\":\"Édifice rural\"}],\"website\":\"http://www.augrandairdeclaviere.fr\",\"email\":\"acavroy@gmail.com\",\"phone\":\"06 33 52 71 83\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"APPVL\",\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07320', NULL, 25221, '07251'),
