(921068, 'musee-des-sports', 'Musée des sports', '07350 Cruas', 'Cruas', 'FR', '44.657132', '4.762564', NULL, '2019-08-23 13:20:33', '2019-08-26 09:26:35', 0, 80369196, '{\"image\":null,\"description\":{\"fr\":\"Espace muséographique renfermant une collection d’objets ayant appartenu à des sportifs locaux, nationaux mais aussi internationaux.\\nSur 250 mètres carrés, les visiteurs peuvent admirer des pièces uniques mais aussi tester leurs capacités physiques sur des simulateurs ou encore prendre la place d’un commentateur sportif le temps d’une course.\"},\"tags\":[{\"id\":15,\"label\":\"Musée, salle d\'exposition\"}],\"website\":\"https://www.cruas.com/Le-musee-des-sports\",\"email\":null,\"phone\":\"+33 4.75.50.80.51\",\"links\":[],\"access\":{\"fr\":\"parkings\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"libre\",\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07350', NULL, 25221, '07076'),
(921200, 'mairie-villeneuve-de-berg139', 'Mairie', '11 Rue Notre-Dame, 07170 Villeneuve-de-Berg', 'Villeneuve-de-Berg', 'FR', '44.556885', '4.500722', NULL, '2019-08-26 08:41:56', '2019-08-26 09:27:06', 0, 94482437, '{\"image\":null,\"description\":{},\"tags\":[],\"email\":null,\"phone\":null,\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null,\"extId\":22}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07170', NULL, 25221, '07341'),
