(921584, 'domaine-marc-seguin-chapelle-de-varagnes', 'Domaine Marc Seguin Chapelle de Varagnes', '7 chemin de Varagnes 07100 Annonay', 'Annonay', 'FR', '45.262332', '4.663816', NULL, '2019-08-26 13:27:33', '2019-08-28 10:04:41', 0, 79091381, '{\"image\":\"location79091381.jpg\",\"description\":{\"fr\":\"Chapelle de Varagnes construite par Marc Seguin vers 1860 et décorée par son fils Augustin Seguin.\"},\"tags\":[{\"id\":42,\"label\":\"Monument historique\"},{\"id\":3,\"label\":\"Édifice religieux\"}],\"website\":\"http://www.fondationseguin.com/index.php/fr/\",\"email\":\"pourlafondationseguin@gmail.com\",\"phone\":\"06 81 41 00 44\",\"links\":[\"https://www.facebook.com/fondation.seguin.innovation/\"],\"access\":{\"fr\":\"Parking gratuit à proximité\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"Cl. V Lefèvre-Seguin\",\"extId\":\"Chapelle de Varagnes\"}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', 'L\'Auvergnat', '07100', NULL, 25221, '07010'),
(921823, 'village-de-saint-martin-de-valamas', 'Village', '10 place de la mairie, 07310 Saint-Martin-de-Valamas', 'Saint-Martin-de-Valamas', 'FR', '44.937149', '4.368848', NULL, '2019-08-28 09:05:17', '2019-08-28 10:04:08', 0, 91723136, '{\"image\":\"location91723136.jpg\",\"description\":{\"fr\":\"Saint Martin de Valamas est un village ancien du haut Vivarais dont la création remonte au-delà du XIe siècle. Le cœur de village permet d\'admirer de vieilles rues aux maisons anciennes et des monuments remarquables comme l\'Arca ou la Tour la Varenne ainsi qu\'un ancien prieuré (XIe siècle) et une croix de pierre sculptée sur deux faces (XVe siècle).\"},\"tags\":[],\"website\":\"http://www.saintmartindevalamas.com\",\"email\":\"mairie@saintmartindevalamas.com\",\"phone\":\"04 75 30 41 76\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"C. Lupovici\",\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07310', NULL, 25221, '07269'),
(922450, 'mairie-darcens', 'Mairie', '125 rue de la Mairie, 07310 Arcens', 'Arcens', 'FR', '44.900066', '4.326097', NULL, '2019-09-01 19:59:00', '2019-09-03 13:48:37', 0, 27638359, '{\"image\":\"location27638359.jpg\",\"description\":{\"fr\":\"Petite commune rurale située dans le Géoparc des Monts d’Ardèche, Arcens compte de nombreuses constructions emblématiques du patrimoine vernaculaire. C’est le cas, en particulier, du Jardin clos au lieu-dit Pré Nouveau, exceptionnel jardin d’imposantes terrasses aménagées (écluse, abri, escaliers « volants », toute construction en phonolite locale). Ce site est construit sur le versant sud du Géosite du Rocher de Soutron (label UNESCO), au-dessus du Hameau de caractère, Massas, où vous pourrez découvrir l’histoire de son four à pain « banal » et de sa fontaine. \\\"\"},\"tags\":[{\"id\":11,\"label\":\"Espace naturel, parc, jardin\"}],\"email\":\"monique.gadais@gmail.com\",\"phone\":\"06 11 02 72 83\",\"links\":[\"https://www.facebook.com/poleharoun.tazieff.7\",\"https://www.fondation-patrimoine.org/les-projets/jardin-clos-du-pre-nouveau-a-arcens\"],\"access\":{\"fr\":\"L\'accueil des visiteurs aura lieu Place de la Mairie, à Arcens, à 13 h 45. Un covoiturage sera organisé pour se rendre au Hameau de Massas. Puis nous marcherons jusqu\'au Jardin clos du Pré Nouveau (transport en voiture possible pour personne à mobilité réduite). Le retour est prévu à 17 heures, à Massa, où un goûter vous attendra\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"Image sous licence libre\",\"extId\":\"Jardin clos du Pré Nouveau\"}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07310', NULL, 25221, '07041'),
(922453, 'hameau-de-massas', 'Hameau Massas & Jardin clos Pré Nouveau', 'Hameau de Massas 07310 Arcens', 'Arcens', 'FR', '44.893656', '4.305675', NULL, '2019-09-01 22:07:50', '2019-09-02 13:56:13', 0, 41253007, '{\"image\":\"location41253007.jpg\",\"description\":{\"fr\":\"Massas, Hameau de la commune d\'Arcens, situé à 2 km du Centre-Bourg, en direction du Gerbier de Jonc, surplombe la Vallée de l\'Eysse. Avec ses anciennes maisons de granite, ses passages voûtés et caladés, ce hameau de caractère comporte également un patrimoine vernaculaire. La lecture des panneaux documentaires vous fera découvrir l\'histoire du four à  pain \\\"banal\\\" et de la fontaine du village. De la fontaine, vous marcherez jusqu\'au Pré Nouveau pour y découvrir son remarquable Jardin clos.\"},\"tags\":[{\"id\":11,\"label\":\"Espace naturel, parc, jardin\"}],\"email\":\"arcade.arcens@gmail.com\",\"phone\":\"06 11 02 72 83\",\"links\":[\"https://www.facebook.com/poleharoun.tazieff.7\",\"https://www.fondation-patrimoine.org/les-projets/jardin-clos-du-pre-nouveau-a-arcens\"],\"access\":{\"fr\":\"Pour vous rendre au Hameau de Massas (au four à pain où vous pourrez laisser votre voiture)), le trajet est balisé depuis le centre Bourg d\'Arcens (pompe à essence sur la D237).\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"Licence libre\",\"extId\":\"Jardin clos Pré Nouveau_VL\"}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07310', NULL, 25221, '07041'),
(923102, 'grotte-saint-marcel', 'Grotte Saint-Marcel', '07700 Bidon', 'Bidon', 'FR', '44.348036', '4.504566', NULL, '2019-09-05 14:45:18', '2019-09-17 08:38:43', 0, 32049550, '{\"image\":null,\"description\":{\"fr\":\"Creusé par une rivière souterraine, le réseau de Saint-Marcel est l\'un des plus vastes d\'Europe. Site de référence pour son intérêt scientifique, il est classé Patrimoine Naturel National depuis 1934\"},\"tags\":[{\"id\":11,\"label\":\"Espace naturel, parc, jardin\"}],\"website\":\"https://www.grotte-ardeche.com/\",\"email\":\"commercial@grotte-ardeche.com\",\"phone\":\"04 75 04 38 07\",\"links\":[\"https://www.facebook.com/grottesaintmarcel/?eid=ARC6L2IEQ6t94oGchXDus2cn5K-tMDvjdMf3D1cpCKKqW62bw4UvBgLgAgC26icAtXFdw8aw9KDlmcVa\"],\"access\":{\"fr\":\"Parking gratuit\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null,\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07700', NULL, 25221, '07034'),
(924302, 'parc-eolien-de-cros-de-georand', 'Parc éolien de Cros-de-Géorand', '07510 Cros-de-Géorand', 'Cros-de-Géorand', 'FR', '44.792300', '4.126810', NULL, '2019-09-12 13:11:34', '2019-09-16 11:02:24', 0, 87316763, '{\"image\":\"location87316763.jpg\",\"description\":{\"fr\":\"Mis en service en 2004, le parc éolien du Plateau Ardéchois est composé de 12 éoliennes qui ont permis d\'alimenter 9 200 personnes par an en électricité propre, mais aussi d\'éviter l\'émission de 125 000 tonnes de CO2 depuis 15 ans.\"},\"tags\":[{\"id\":8,\"label\":\"Édifice industriel, scientifique et technique\"}],\"email\":\"15ansplateauardechois@res-group.com\",\"phone\":\"04 27 01 26 17\",\"links\":[],\"access\":{\"fr\":\"Suivez les indications depuis la Route Départementale 122, entre le Béage et Saint-Eulalie\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"RES\",\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07510', NULL, 25221, '07026');
INSERT INTO `location` (`id`, `slug`, `placename`, `address`, `city`, `country`, `latitude`, `longitude`, `owner_id`, `created_at`, `updated_at`, `main`, `uid`, `store`, `processed_at`, `department`, `region`, `city_district`, `postal_code`, `eve_id`, `agenda_id`, `insee`, `set_uid`, `ext_id`) VALUES
(924675, '400-rue-de-vidalon-07430-davezieux', 'Église Notre-Dame de l\'usine de Vidalon', '400 rue de Vidalon 07430 Davézieux', 'Davézieux', 'FR', '45.254431', '4.680093', NULL, '2019-09-13 11:30:26', '2019-09-16 12:23:33', 0, 30433085, '{\"image\":\"location30433085.jpg\",\"description\":{\"fr\":\"Église Notre-Dame de l\'Usine de Vidalon\\n\\n\\nAncienne chapelle des Papeteries Canson et Montgolfier, inaugurée en 1877, elle marque l’entrée de la cité ouvrière.\\n De style  néo-gothique, elle est l\'œuvre de l’architecte  Prosper Borione. Elle est dédiée à Notre-Dame de l\'Usine dont on peut admirer une statue.\\nSes vitraux ornés représentent essentiellement les saints patrons des membres de la famille Montgolfier qui finança l’édifice.\\nEn 1880, on y installe l\'ancien orgue de la collégiale Notre-Dame d\'Annonay. Il a été classé monument historique en 1980.\\nLe site des Papeteries Canson-Montgolfier de Vidalon, dont l\'église, est inscrit à l\'inventaire des Monuments Historiques depuis 2012.\"},\"tags\":[{\"id\":42,\"label\":\"Monument historique\"},{\"id\":3,\"label\":\"Édifice religieux\"}],\"email\":null,\"phone\":\"0475698920\",\"links\":[],\"access\":{\"fr\":\"Parking devant l\'église\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"MHR\",\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', 'Cheval Sud', '07430', NULL, 25221, '07078', 1903810, 'ard_01'),
(973787, 'st-andre-lachamp', 'St André Lachamp', 'St André Lachamp', 'Saint-André-Lachamp', 'FR', '44.505206', '4.163861', NULL, '2020-06-12 17:34:54', '2020-06-12 17:34:55', 0, 7630649, '{\"image\":\"location7630649.jpg\",\"description\":{\"fr\":\"Visite commentée de l\'église St Pierre aux Liens. Église à clocher peigne du XII ème\"},\"tags\":[{\"id\":42,\"label\":\"Monument historique\"},{\"id\":51,\"label\":\"Site patrimonial remarquable\"},{\"id\":32,\"label\":\"Ouverture exceptionnelle\"},{\"id\":3,\"label\":\"Édifice religieux\"}],\"email\":\"thierry.gouin@free.fr\",\"phone\":\"04 75 39 49 75\",\"links\":[],\"access\":{\"fr\":\"Accés libre, parking à proximité.\"},\"state\":0,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"Licence libre\",\"extId\":\"leg_ard_03\"}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', 'Les prés de Lachamp', '07230', NULL, 25221, '07213', 1903810, NULL),
(976778, 'saint-paul-le-jeune', 'Saint-Paul-le-Jeune', '07460 Saint-Paul-le-Jeune', 'Saint-Paul-le-Jeune', 'FR', '44.339599', '4.153617', NULL, '2020-06-23 11:09:02', '2020-06-23 11:09:02', 0, 60763721, '{\"image\":\"location60763721.jpg\",\"description\":{\"fr\":\"Au départ de la place de la Gare, une balade guidée sur les hauts de Saint-Paul-le-Jeune à la découverte des dolmens, d\'une carrière de pierres, des lavoirs, des hameaux ou encore des vestiges de la voie ferrée.\"},\"tags\":[{\"id\":33,\"label\":\"Première participation\"},{\"id\":9,\"label\":\"Édifice rural\"},{\"id\":11,\"label\":\"Espace naturel, parc, jardin\"},{\"id\":16,\"label\":\"Site archéologique\"},{\"id\":8,\"label\":\"Édifice industriel, scientifique et technique\"}],\"email\":\"dolmen@cc-gorgesardeche.fr\",\"phone\":\"07 89 00 33 74\",\"links\":[\"http://www.facebook.com/cheminsetdolmens\"],\"access\":{\"fr\":\"Parking de la Gare\"},\"state\":0,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"Chemins et Dolmens\",\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', 'La gare', '07460', NULL, 25221, '07024', 1903810, 'ard_04');
