(925729, 'grotte-chauvet-2-ardeche327', 'Grotte Chauvet 2 - Ardèche', '07150 Vallon Pont d\'Arc', 'Vallon-Pont-d\'Arc', 'FR', '44.406684', '4.429893', NULL, '2019-09-20 07:21:41', '2020-04-28 14:25:01', 0, 51665987, '{\"image\":\"location51665985.jpg\",\"description\":{\"fr\":\"Revenez aux origines de l’art et découvrez le 1er grand chef d\'œuvre de l\'humanité daté d\'il y a 36.000 ans : des centaines d\'animaux dessinés sur le vif, chassant, courant ou s\'affrontant. Site réplique de la grotte Chauvet qui a bouleversé l\'histoire de l\'humanité.\"},\"tags\":[{\"id\":37,\"label\":\"Patrimoine mondial de l\'UNESCO\"},{\"id\":39,\"label\":\"Tourisme et handicap\"},{\"id\":16,\"label\":\"Site archéologique\"}],\"website\":\"http://www.grottechauvet2ardeche.com\",\"email\":\"infos@grottechauvet2ardeche.com\",\"phone\":\"+33(0)4 75 94 39 40\",\"links\":[],\"access\":{},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":\"Grotte Chauvet 2 - Ardèche\",\"extId\":null}', NULL, 'Ardèche', 'Auvergne-Rhône-Alpes', NULL, '07150', NULL, 25221, '07330', 1903810, 'ard_02', 0, '{\"candidates\":[51665986], \"disqualified\":[5]}', null),
